package com.example.rag.controller;

import com.example.rag.entity.ChatMessage;
import com.example.rag.repository.ChatMessageRepository;
import com.example.rag.service.ChatBotService;
import com.example.rag.service.FileUploadService;
import org.springframework.ai.chat.memory.ChatMemoryRepository;
import org.springframework.ai.chat.messages.Message;
import org.springframework.ai.chat.messages.MessageType;
import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;

import java.util.*;

@Controller
public class ChatController {

    private final ChatBotService chatBotService;
    private final FileUploadService fileUploadService;
    private final ChatMemoryRepository memoryRepository;
    private final ChatMessageRepository chatMessageRepo;

    public ChatController(ChatBotService chatBotService,
                          FileUploadService fileUploadService,
                          ChatMemoryRepository memoryRepository,
                          ChatMessageRepository chatMessageRepo) {
        this.chatBotService = chatBotService;
        this.fileUploadService = fileUploadService;
        this.memoryRepository = memoryRepository;
        this.chatMessageRepo = chatMessageRepo;
    }

    @GetMapping("/")
    public String index() {
        return "index";
    }

    /* ── Chat ── */
    @PostMapping("/api/chat")
    @ResponseBody
    public ResponseEntity<Map<String, String>> chat(@RequestBody Map<String, String> body) {
        String message = body.get("message");
        if (message == null || message.isBlank()) {
            return ResponseEntity.badRequest().body(Map.of("error", "Message is required"));
        }
        String sessionId = body.getOrDefault("sessionId", UUID.randomUUID().toString());

        // Do NOT auto-create Conversation here. Conversation titles are managed separately
        // (e.g. renamed by user or set by chatbot logic). Keep this method minimal.

        String response = chatBotService.chat(message, sessionId);
        return ResponseEntity.ok(Map.of("response", response, "sessionId", sessionId));
    }

    /* ── Session: list all conversation IDs with first message preview ── */
    @GetMapping("/api/sessions")
    @ResponseBody
    public ResponseEntity<List<Map<String, Object>>> listSessions() {
        List<String> ids = memoryRepository.findConversationIds();
        List<Map<String, Object>> result = new ArrayList<>();
        for (String id : ids) {
            List<Message> msgs = memoryRepository.findByConversationId(id);
            // Find first user message for title preview
            String title = msgs.stream()
                    .filter(m -> m.getMessageType() == MessageType.USER)
                    .findFirst()
                    .map(m -> truncate(m.getText(), 60))
                    .orElse("New Conversation");
            Map<String, Object> entry = new LinkedHashMap<>();
            entry.put("id", id);
            entry.put("title", title);
            entry.put("messageCount", msgs.size());
            result.add(entry);
        }
        return ResponseEntity.ok(result);
    }

    /* ── Session: get all messages for a conversation ── */
    @GetMapping("/api/sessions/{sessionId}/messages")
    @ResponseBody
    public ResponseEntity<Map<String, Object>> getSessionMessages(@PathVariable String sessionId) {
        List<Message> msgs = memoryRepository.findByConversationId(sessionId);
        List<Map<String, String>> list = new ArrayList<>();
        for (Message m : msgs) {
            if (m.getMessageType() == MessageType.SYSTEM) continue; // skip system messages
            list.add(Map.of(
                    "role", m.getMessageType().getValue(),
                    "content", m.getText()
            ));
        }
        return ResponseEntity.ok(Map.of("messages", list));
    }

    /* ── Session: delete a conversation ── */
    @DeleteMapping("/api/sessions/{sessionId}")
    @ResponseBody
    public ResponseEntity<Map<String, String>> deleteSession(@PathVariable String sessionId) {
        memoryRepository.deleteByConversationId(sessionId);
        return ResponseEntity.ok(Map.of("message", "Deleted"));
    }

    /* ── Session: start a new conversation (clears old one) ── */
    @PostMapping("/api/chat/clear")
    @ResponseBody
    public ResponseEntity<Map<String, String>> clearChat(@RequestBody Map<String, String> body) {
        String sessionId = body.get("sessionId");
        if (sessionId != null && !sessionId.isBlank()) {
            chatBotService.clearSession(sessionId);
        }
        return ResponseEntity.ok(Map.of(
                "sessionId", UUID.randomUUID().toString(),
                "message", "New conversation started"
        ));
    }

    /* ── File upload ── */
    @PostMapping("/api/upload")
    @ResponseBody
    public ResponseEntity<Map<String, String>> upload(@RequestParam("file") MultipartFile file) {
        try {
            String result = fileUploadService.processFile(file);
            return ResponseEntity.ok(Map.of("message", result));
        } catch (Exception e) {
            return ResponseEntity.internalServerError().body(Map.of("error", e.getMessage()));
        }
    }

    @GetMapping("/history/{sessionId}")
    public ResponseEntity<List<ChatMessage>> getHistory(@PathVariable String sessionId) {
        return ResponseEntity.ok(chatMessageRepo.findBySessionIdOrderByCreatedAtAsc(sessionId));
    }

    private String truncate(String s, int maxLen) {
        if (s == null) return "";
        return s.length() <= maxLen ? s : s.substring(0, maxLen) + "…";
    }
}

package com.example.rag.controller;

import com.example.rag.entity.ChatMessage;
import com.example.rag.entity.Conversation;
import com.example.rag.repository.ChatMessageRepository;
import com.example.rag.repository.ConversationRepository;
import com.example.rag.service.ChatBotService;
import com.example.rag.service.FileUploadService;
import org.springframework.ai.chat.memory.ChatMemoryRepository;
import org.springframework.ai.chat.messages.Message;
import org.springframework.ai.chat.messages.MessageType;
import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;

import java.util.*;

@Controller
public class ChatController {

    private final ChatBotService chatBotService;
    private final FileUploadService fileUploadService;
    private final ChatMemoryRepository memoryRepository;
    private final ChatMessageRepository chatMessageRepo;
    private final ConversationRepository conversationRepository;

    public ChatController(ChatBotService chatBotService,
                          FileUploadService fileUploadService,
                          ChatMemoryRepository memoryRepository,
                          ChatMessageRepository chatMessageRepo,
                          ConversationRepository conversationRepository) {
        this.chatBotService = chatBotService;
        this.fileUploadService = fileUploadService;
        this.memoryRepository = memoryRepository;
        this.chatMessageRepo = chatMessageRepo;
        this.conversationRepository = conversationRepository;
    }

    @GetMapping("/")
    public String index() {
        return "index";
    }

    /* ── Chat ── */
    @PostMapping("/api/chat")
    @ResponseBody
    public ResponseEntity<Map<String, String>> chat(@RequestBody Map<String, String> body) {
        String message = body.get("message");
        if (message == null || message.isBlank()) {
            return ResponseEntity.badRequest().body(Map.of("error", "Message is required"));
        }
        String sessionId = body.getOrDefault("sessionId", UUID.randomUUID().toString());

        // Do NOT auto-create Conversation here. Conversation titles are managed separately
        // by the rename endpoint when the user edits the title.

        String response = chatBotService.chat(message, sessionId);
        return ResponseEntity.ok(Map.of("response", response, "sessionId", sessionId));
    }

    /* ── Session: list all conversation IDs with first message preview ── */
    @GetMapping("/api/sessions")
    @ResponseBody
    public ResponseEntity<List<Map<String, Object>>> listSessions() {
        List<String> ids = memoryRepository.findConversationIds();
        List<Map<String, Object>> result = new ArrayList<>();
        for (String id : ids) {
            List<Message> msgs = memoryRepository.findByConversationId(id);
            // Prefer stored conversation title if present
            String title = conversationRepository.findById(id)
                    .map(Conversation::getTitle)
                    .orElseGet(() -> msgs.stream()
                            .filter(m -> m.getMessageType() == MessageType.USER)
                            .findFirst()
                            .map(m -> truncate(m.getText(), 60))
                            .orElse("New Conversation")
                    );
            Map<String, Object> entry = new LinkedHashMap<>();
            entry.put("id", id);
            entry.put("title", title);
            entry.put("messageCount", msgs.size());
            result.add(entry);
        }
        return ResponseEntity.ok(result);
    }

    /* ── Session: get all messages for a conversation ── */
    @GetMapping("/api/sessions/{sessionId}/messages")
    @ResponseBody
    public ResponseEntity<Map<String, Object>> getSessionMessages(@PathVariable String sessionId) {
        List<Message> msgs = memoryRepository.findByConversationId(sessionId);
        List<Map<String, String>> list = new ArrayList<>();
        for (Message m : msgs) {
            if (m.getMessageType() == MessageType.SYSTEM) continue; // skip system messages
            list.add(Map.of(
                    "role", m.getMessageType().getValue(),
                    "content", m.getText()
            ));
        }
        return ResponseEntity.ok(Map.of("messages", list));
    }

    /* ── Session: rename a conversation ── */
    @PutMapping("/api/sessions/{sessionId}/rename")
    @ResponseBody
    public ResponseEntity<Map<String, String>> renameSession(@PathVariable String sessionId,
                                                             @RequestBody Map<String, String> body) {
        String title = body.get("title");
        if (title == null) {
            return ResponseEntity.badRequest().body(Map.of("error", "Title is required"));
        }
        // create or update Conversation record
        Conversation conv = conversationRepository.findById(sessionId).orElseGet(() -> {
            Conversation c = new Conversation();
            c.setSessionId(sessionId);
            return c;
        });
        conv.setTitle(title.trim().isEmpty() ? "New Conversation" : title.trim());
        conversationRepository.save(conv);
        return ResponseEntity.ok(Map.of("message", "Renamed", "title", conv.getTitle()));
    }

    /* ── Session: delete a conversation ── */
    @DeleteMapping("/api/sessions/{sessionId}")
    @ResponseBody
    public ResponseEntity<Map<String, String>> deleteSession(@PathVariable String sessionId) {
        memoryRepository.deleteByConversationId(sessionId);
        conversationRepository.deleteById(sessionId);
        return ResponseEntity.ok(Map.of("message", "Deleted"));
    }

    /* ── Session: start a new conversation (clears old one) ── */
    @PostMapping("/api/chat/clear")
    @ResponseBody
    public ResponseEntity<Map<String, String>> clearChat(@RequestBody Map<String, String> body) {
        String sessionId = body.get("sessionId");
        if (sessionId != null && !sessionId.isBlank()) {
            chatBotService.clearSession(sessionId);
            conversationRepository.deleteById(sessionId);
        }
        return ResponseEntity.ok(Map.of(
                "sessionId", UUID.randomUUID().toString(),
                "message", "New conversation started"
        ));
    }

    /* ── File upload ── */
    @PostMapping("/api/upload")
    @ResponseBody
    public ResponseEntity<Map<String, String>> upload(@RequestParam("file") MultipartFile file) {
        try {
            String result = fileUploadService.processFile(file);
            return ResponseEntity.ok(Map.of("message", result));
        } catch (Exception e) {
            return ResponseEntity.internalServerError().body(Map.of("error", e.getMessage()));
        }
    }

    @GetMapping("/history/{sessionId}")
    public ResponseEntity<List<ChatMessage>> getHistory(@PathVariable String sessionId) {
        return ResponseEntity.ok(chatMessageRepo.findBySessionIdOrderByCreatedAtAsc(sessionId));
    }

    private String truncate(String s, int maxLen) {
        if (s == null) return "";
        return s.length() <= maxLen ? s : s.substring(0, maxLen) + "…";
    }
}

package com.example.rag.entity;

import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.Id;
import jakarta.persistence.Table;
import lombok.Data;

import java.time.LocalDateTime;

@Data
@Entity
@Table(name = "conversations")
public class Conversation {

    @Id
    @Column(name = "session_id", nullable = false)
    private String sessionId;

    @Column(nullable = false)
    private String title = "New Conversation";

    @Column(name = "created_at")
    private LocalDateTime createdAt = LocalDateTime.now();
}

package com.example.rag.repository;

import com.example.rag.entity.Conversation;
import org.springframework.data.jpa.repository.JpaRepository;

public interface ConversationRepository extends JpaRepository<Conversation, String> {
}

--DROP TABLE IF EXISTS chat_messages;

-- Ensure idempotent initialization: do not fail if table already exists
CREATE TABLE IF NOT EXISTS chat_messages (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    session_id VARCHAR(255) NOT NULL,
    role VARCHAR(50) NOT NULL,
    content CLOB NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

--DROP TABLE IF EXISTS chat_messages;

-- Ensure idempotent initialization: do not fail if table already exists
CREATE TABLE IF NOT EXISTS chat_messages (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    session_id VARCHAR(255) NOT NULL,
    role VARCHAR(50) NOT NULL,
    content CLOB NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Conversations table for storing user-custom titles
CREATE TABLE IF NOT EXISTS conversations (
    session_id VARCHAR(255) PRIMARY KEY,
    title VARCHAR(255) NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

/* ── Reset & Variables ─────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
    --accent:        #ff7c1d;
    --accent-hover:  #e86e10;
    --accent-dim:    #fff3e8;
    --accent-border: #fddcbb;
    --bg:            #ffffff;
    --sidebar-bg:    #f7f8fa;
    --sidebar-hover: #eff0f1;
    --sidebar-active:#fff3e8;
    --border:        #e5e7eb;
    --border-2:      #d1d5db;
    --text-1:        #111827;
    --text-2:        #4b5563;
    --text-3:        #9ca3af;
    --bot-bg:        #f7f8fa;
    --user-bg:       #fff3e8;
    --user-border:   #fddcbb;
    --green:         #16a34a;
    --red:           #dc2626;
    --shadow-sm:     0 1px 3px rgba(0,0,0,.07);
    --shadow-md:     0 4px 16px rgba(0,0,0,.10);
    --radius:        10px;
    --transition:    all .15s ease;
}

html, body {
    height: 100%;
    font-family: Inter, system-ui, -apple-system, sans-serif;
    font-size: 14px;
    line-height: 1.5;
    color: var(--text-1);
    background: var(--bg);
    -webkit-font-smoothing: antialiased;
}

/* ── App Shell ─────────────────────────────────────────── */
.app {
    display: flex;
    height: 100vh;
    overflow: hidden;
}

/* ── Sidebar ───────────────────────────────────────────── */
.sidebar {
    width: 260px;
    min-width: 260px;
    background: var(--sidebar-bg);
    border-right: 1px solid var(--border);
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

/* Header */
.sidebar-header {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 14px 12px 12px;
    border-bottom: 1px solid var(--border);
    background: var(--bg);
}

.logo {
    display: flex;
    align-items: center;
    gap: 8px;
    flex: 1;
}

.logo-icon {
    width: 28px;
    height: 28px;
    background: var(--accent);
    color: #fff;
    border-radius: 7px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 14px;
    font-weight: 800;
    letter-spacing: -1px;
}

.logo-text  { font-size: 15px; font-weight: 700; color: var(--text-1); }
.logo-accent{ color: var(--accent); }

.new-chat-btn {
    display: inline-flex;
    align-items: center;
    gap: 5px;
    background: var(--accent);
    color: #fff;
    border: none;
    border-radius: 7px;
    padding: 6px 11px;
    font-size: 12px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: var(--transition);
    white-space: nowrap;
}
.new-chat-btn:hover { background: var(--accent-hover); }

/* ── Conversation List ─────────────────────────────────── */
.conv-list {
    flex: 1;
    overflow-y: auto;
    padding: 6px 0;
}
.conv-list::-webkit-scrollbar { width: 3px; }
.conv-list::-webkit-scrollbar-thumb { background: var(--border-2); border-radius: 2px; }

.conv-group-label {
    font-size: 10.5px;
    font-weight: 700;
    color: var(--text-3);
    text-transform: uppercase;
    letter-spacing: .06em;
    padding: 10px 14px 3px;
}

.conv-item {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 7px 12px;
    margin: 1px 6px;
    border-radius: 7px;
    cursor: pointer;
    transition: background .1s;
    position: relative;
    border-left: 2px solid transparent;
}
.conv-item:hover             { background: var(--sidebar-hover); }
.conv-item.active            { background: var(--sidebar-active); border-left-color: var(--accent); }

.conv-icon {
    color: var(--text-3);
    flex-shrink: 0;
}
.conv-item.active .conv-icon { color: var(--accent); }

.conv-title {
    flex: 1;
    font-size: 13px;
    color: var(--text-1);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}
.conv-item.active .conv-title { font-weight: 600; }

.conv-delete {
    display: none;
    align-items: center;
    justify-content: center;
    background: none;
    border: none;
    color: var(--text-3);
    cursor: pointer;
    padding: 3px;
    border-radius: 4px;
    flex-shrink: 0;
    transition: var(--transition);
}
.conv-item:hover .conv-delete  { display: flex; }
.conv-delete:hover             { background: var(--border); color: var(--red); }

.conv-empty {
    text-align: center;
    color: var(--text-3);
    font-size: 12px;
    padding: 24px 16px;
    line-height: 1.6;
}

/* ── Knowledge Base Section ───────────────────────────── */
.sidebar-knowledge {
    border-top: 1px solid var(--border);
}

.knowledge-toggle {
    width: 100%;
    display: flex;
    align-items: center;
    gap: 7px;
    padding: 11px 14px;
    background: none;
    border: none;
    font-family: inherit;
    font-size: 12.5px;
    font-weight: 600;
    color: var(--text-2);
    cursor: pointer;
    transition: color .15s;
}
.knowledge-toggle:hover        { color: var(--accent); }
.knowledge-toggle .arrow       { margin-left: auto; transition: transform .2s; }
.knowledge-toggle.open .arrow  { transform: rotate(180deg); }

.knowledge-body                { padding: 0 10px 12px; display: none; }
.knowledge-body.open           { display: block; }

/* Drop zone */
.drop-zone {
    border: 1.5px dashed var(--border-2);
    border-radius: 8px;
    padding: 14px 10px;
    text-align: center;
    cursor: pointer;
    transition: var(--transition);
}
.drop-zone:hover, .drop-zone.drag-over {
    border-color: var(--accent);
    background: var(--accent-dim);
}
.drop-zone input { display: none; }

.drop-icon-sm { font-size: 18px; margin-bottom: 4px; color: var(--text-3); }
.drop-label   { font-size: 11.5px; font-weight: 600; color: var(--text-2); }
.drop-sub     { font-size: 10.5px; color: var(--text-3); margin-top: 2px; }

/* Progress */
.progress-bar-wrap  { margin: 8px 0 2px; }
.progress-bar-bg    { height: 3px; background: var(--border); border-radius: 2px; }
.progress-fill      { height: 100%; background: var(--accent); border-radius: 2px; width: 0; transition: width .2s; }
.progress-label     { font-size: 10.5px; color: var(--text-3); display: block; margin-top: 3px; }

/* File list */
.file-list-sm       { list-style: none; margin-top: 8px; max-height: 100px; overflow-y: auto; }
.file-item-sm {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 11px;
    color: var(--text-2);
    padding: 4px 2px;
    border-bottom: 1px solid var(--border);
}
.file-item-sm:last-child { border-bottom: none; }

/* ── Main Chat Area ────────────────────────────────────── */
.main {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    background: var(--bg);
}

/* ── Messages ─────────────────────────────────────────── */
.messages {
    flex: 1;
    overflow-y: auto;
    padding: 24px 0 8px;
    display: flex;
    flex-direction: column;
    gap: 2px;
}
.messages::-webkit-scrollbar       { width: 5px; }
.messages::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }

/* Message row */
.message {
    display: flex;
    align-items: flex-start;
    gap: 12px;
    padding: 6px 28px;
}
.message-user { flex-direction: row-reverse; }

/* Avatar */
.avatar {
    width: 32px;
    height: 32px;
    min-width: 32px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 11px;
    font-weight: 700;
    flex-shrink: 0;
}
.bot-avatar  { background: var(--accent); color: #fff; }
.user-avatar { background: #e5e7eb; color: var(--text-2); border: 1px solid var(--border-2); }

/* Bubble */
.message-content {
    max-width: 680px;
    padding: 12px 16px;
    line-height: 1.75;
    word-break: break-word;
    font-size: 14px;
    border-radius: 16px;
}
.message-bot  .message-content {
    background: var(--bot-bg);
    border-bottom-left-radius: 4px;
    color: var(--text-1);
}
.message-user .message-content {
    background: var(--user-bg);
    border: 1px solid var(--user-border);
    border-bottom-right-radius: 4px;
    color: var(--text-1);
}

/* Typing dots */
.dots         { display: flex; gap: 5px; padding: 2px 0; }
.dots span    { width: 7px; height: 7px; background: var(--text-3); border-radius: 50%; animation: bounce 1.2s infinite; }
.dots span:nth-child(2) { animation-delay: .2s; }
.dots span:nth-child(3) { animation-delay: .4s; }
@keyframes bounce {
    0%, 60%, 100% { transform: translateY(0); }
    30%            { transform: translateY(-7px); }
}

/* Markdown inside messages */
.message-content p         { margin: 0 0 10px; }
.message-content p:last-child { margin: 0; }
.message-content h1,
.message-content h2,
.message-content h3        { margin: 14px 0 6px; font-weight: 700; line-height: 1.3; }
.message-content h1        { font-size: 18px; }
.message-content h2        { font-size: 16px; }
.message-content h3        { font-size: 14px; }
.message-content strong    { font-weight: 600; }
.message-content em        { font-style: italic; }
.message-content code      {
    font-family: 'JetBrains Mono', monospace;
    font-size: 12.5px;
    background: rgba(0,0,0,.06);
    padding: 1px 5px;
    border-radius: 4px;
}
.message-content pre       {
    background: #1e1e2e;
    color: #cdd6f4;
    padding: 14px 16px;
    border-radius: 8px;
    overflow-x: auto;
    margin: 10px 0;
}
.message-content pre code  { background: none; color: inherit; padding: 0; font-size: 13px; }
.message-content ul,
.message-content ol        { margin: 8px 0 8px 20px; }
.message-content li        { margin-bottom: 4px; }
.message-content blockquote{
    border-left: 3px solid var(--accent);
    margin: 10px 0;
    padding: 6px 12px;
    background: var(--accent-dim);
    border-radius: 0 6px 6px 0;
    color: var(--text-2);
}

/* ── Welcome Card ─────────────────────────────────────── */
.welcome-card {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    text-align: center;
    padding: 40px 32px;
    max-width: 620px;
    margin: 0 auto;
    width: 100%;
    gap: 12px;
}

.welcome-icon {
    width: 58px;
    height: 58px;
    background: var(--accent-dim);
    border: 1px solid var(--accent-border);
    border-radius: 14px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--accent);
    margin-bottom: 6px;
}

.welcome-title {
    font-size: 24px;
    font-weight: 700;
    letter-spacing: -.4px;
    color: var(--text-1);
}

.welcome-sub {
    font-size: 14.5px;
    color: var(--text-2);
    line-height: 1.7;
    max-width: 460px;
}
.welcome-sub strong { color: var(--accent); font-weight: 600; }

.welcome-chips {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    justify-content: center;
    margin-top: 10px;
}

.chip {
    background: var(--sidebar-bg);
    border: 1px solid var(--border);
    color: var(--text-2);
    font-size: 13px;
    font-weight: 500;
    padding: 8px 16px;
    border-radius: 20px;
    cursor: pointer;
    transition: var(--transition);
    font-family: inherit;
    user-select: none;
}
.chip:hover { background: var(--accent-dim); border-color: var(--accent-border); color: var(--accent); }

/* ── Input Area ───────────────────────────────────────── */
.input-area {
    padding: 14px 28px 18px;
    border-top: 1px solid var(--border);
    background: var(--bg);
}

.input-box {
    display: flex;
    align-items: flex-end;
    gap: 8px;
    border: 1.5px solid var(--border-2);
    border-radius: 13px;
    padding: 8px 8px 8px 12px;
    background: var(--bg);
    transition: border-color .15s, box-shadow .15s;
}
.input-box:focus-within {
    border-color: var(--accent);
    box-shadow: 0 0 0 3px rgba(255,124,29,.08);
}

.attach-btn {
    background: none;
    border: none;
    color: var(--text-3);
    cursor: pointer;
    padding: 5px 6px;
    border-radius: 7px;
    display: flex;
    align-items: center;
    transition: var(--transition);
    flex-shrink: 0;
}
.attach-btn:hover { background: var(--sidebar-bg); color: var(--accent); }

.message-input {
    flex: 1;
    border: none;
    outline: none;
    resize: none;
    font-family: inherit;
    font-size: 14px;
    color: var(--text-1);
    background: transparent;
    max-height: 150px;
    line-height: 1.6;
    padding: 5px 0;
}
.message-input::placeholder { color: var(--text-3); }

.send-btn {
    width: 34px;
    height: 34px;
    min-width: 34px;
    background: var(--accent);
    border: none;
    border-radius: 9px;
    color: #fff;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background .15s;
    flex-shrink: 0;
}
.send-btn:hover    { background: var(--accent-hover); }
.send-btn:disabled { background: var(--border-2); cursor: not-allowed; }

.input-hint {
    font-size: 11px;
    color: var(--text-3);
    margin-top: 7px;
    text-align: center;
}
.input-hint kbd {
    background: #f0f0f0;
    border: 1px solid var(--border-2);
    border-radius: 3px;
    padding: 1px 5px;
    font-size: 10px;
    font-family: monospace;
}

/* ── Toast ────────────────────────────────────────────── */
.toast {
    position: fixed;
    bottom: 24px;
    right: 24px;
    padding: 10px 18px;
    border-radius: 8px;
    font-size: 13px;
    font-weight: 500;
    z-index: 9999;
    opacity: 0;
    pointer-events: none;
    transform: translateY(8px);
    transition: all .2s;
    max-width: 320px;
}
.toast.show       { opacity: 1; transform: translateY(0); pointer-events: auto; }
.toast-success    { background: #16a34a; color: #fff; }
.toast-error      { background: #dc2626; color: #fff; }
.toast-default    { background: var(--text-1); color: #fff; }

/* ── Code Blocks ──────────────────────────────────────── */
/* Code block wrapper + toolbar for expand/copy and resizable blocks */
.code-wrap {
    position: relative;
    margin: 10px 0;
}
.code-wrap .code-toolbar {
    position: absolute;
    top: 8px;
    right: 8px;
    display: flex;
    gap: 6px;
    z-index: 6;
}
.code-btn {
    background: rgba(255,255,255,0.06);
    border: 1px solid rgba(255,255,255,0.06);
    color: #cdd6f4;
    padding: 4px 8px;
    border-radius: 6px;
    font-size: 12px;
    cursor: pointer;
    backdrop-filter: blur(2px);
}
.code-btn:hover { background: rgba(255,255,255,0.10); }

/* Toolbar copy button styling and tooltip (uses data-tooltip attr) */
.code-btn.code-copy-btn {
    background: rgba(0,0,0,0.28);
    border: none;
    color: #fff;
    padding: 8px;
    border-radius: 8px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    transition: background .12s ease, transform .12s ease;
}
.code-btn.code-copy-btn svg { opacity: 0.95; }
.code-btn.code-copy-btn:hover { background: rgba(0,0,0,0.42); transform: translateY(-2px); }
.code-btn.code-copy-btn.copied { background: #10b981; box-shadow: 0 8px 22px rgba(16,185,129,0.18); }

/* data-tooltip pseudo element for small hover label */
.code-btn[data-tooltip] {
    position: relative;
}
.code-btn[data-tooltip]::after {
    content: attr(data-tooltip);
    position: absolute;
    top: -36px;
    right: 0;
    transform: translateY(6px);
    background: rgba(17,24,39,0.95);
    color: #fff;
    padding: 6px 8px;
    border-radius: 6px;
    font-size: 12px;
    opacity: 0;
    pointer-events: none;
    transition: opacity .12s, transform .12s;
    white-space: nowrap;
}
.code-btn[data-tooltip]:hover::after { opacity: 1; transform: translateY(0); }

/* Smooth overlay open/close */
.code-wrap {
    transition: transform .18s cubic-bezier(.2,.9,.3,1), box-shadow .18s;
}
.code-wrap.expanded {
    transform: scale(1.01);
}
.code-wrap.expanded { animation: overlayIn .14s ease; }
@keyframes overlayIn { from { opacity: 0; transform: translateY(6px) scale(.998); } to { opacity: 1; transform: translateY(0) scale(1); } }

/* Ensure toolbar sits above pre content */
.code-toolbar { z-index: 12; }

/* Expanded overlay mode */
.code-wrap.expanded {
    position: fixed;
    top: 5vh;
    left: 5vw;
    right: 5vw;
    bottom: 5vh;
    z-index: 9999;
    display: flex;
    flex-direction: column;
    background: rgba(17,20,26,0.96);
    padding: 12px;
    border-radius: 10px;
    box-shadow: 0 10px 40px rgba(2,6,23,0.6);
}
.code-wrap.expanded pre {
    flex: 1 1 auto;
    width: 100% !important;
    height: 100% !important;
    max-height: none !important;
    overflow: auto !important;
}

/* Ensure code-wrap can expand wider than the message bubble but not exceed viewport */
.message-content .code-wrap {
    width: auto;
    max-width: 90vw; /* allow horizontal expansion up to viewport */
}
.message-content .code-wrap pre {
    width: 100%;
    box-sizing: border-box;
    white-space: pre; /* preserve whitespace; prevents forced wrapping inside code by default */
}

/* Ensure pre remains visually distinct and can be resized when not expanded */
.message-content pre {
    resize: both;
    min-width: 220px;
    min-height: 80px;
}

/* Floating copy button (right-middle) */
.code-copy-float {
    position: absolute;
    top: 12px;
    right: 12px;
    background: rgba(0,0,0,0.48);
    border: none;
    color: #fff;
    padding: 8px;
    width: 40px;
    height: 40px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border-radius: 8px;
    cursor: pointer;
    transition: transform .12s ease, background .12s ease, box-shadow .12s ease;
    z-index: 8;
    box-shadow: 0 6px 18px rgba(2,6,23,0.45);
}
.code-copy-float svg { opacity: 0.95; }
.code-copy-float:hover { transform: translateY(-3px); background: rgba(0,0,0,0.62); }
.code-copy-float.copied { background: #10b981; transform: scale(1.05); box-shadow: 0 8px 22px rgba(16,185,129,0.18); }

/* When overlay expanded, move floating button to top-right and adjust color to match dark overlay */
.code-wrap.expanded .code-copy-float {
    top: 12px;
    right: 16px;
    background: rgba(255,255,255,0.06);
    color: #cdd6f4;
}

/* Slightly reduce toolbar size so copy float is primary control */
.code-toolbar { opacity: 0.95; }
.code-toolbar .code-btn { padding: 6px; width: 36px; height: 36px; display: inline-flex; align-items: center; justify-content: center; }

/* Ensure code-wrap has a subtle border when not expanded to separate from background */
.code-wrap { outline: 1px solid rgba(0,0,0,0.04); }

/* ── Responsive ───────────────────────────────────────── */
@media (max-width: 640px) {
    .sidebar         { display: none; }
    .message         { padding: 4px 14px; }
    .input-area      { padding: 12px 14px 16px; }
    .welcome-title   { font-size: 20px; }
}

/* ── Reset & Variables ─────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
    --accent:        #ff7c1d;
    --accent-hover:  #e86e10;
    --accent-dim:    #fff3e8;
    --accent-border: #fddcbb;
    --bg:            #ffffff;
    --sidebar-bg:    #f7f8fa;
    --sidebar-hover: #eff0f1;
    --sidebar-active:#fff3e8;
    --border:        #e5e7eb;
    --border-2:      #d1d5db;
    --text-1:        #111827;
    --text-2:        #4b5563;
    --text-3:        #9ca3af;
    --bot-bg:        #f7f8fa;
    --user-bg:       #fff3e8;
    --user-border:   #fddcbb;
    --green:         #16a34a;
    --red:           #dc2626;
    --shadow-sm:     0 1px 3px rgba(0,0,0,.07);
    --shadow-md:     0 4px 16px rgba(0,0,0,.10);
    --radius:        10px;
    --transition:    all .15s ease;
}

html, body {
    height: 100%;
    font-family: Inter, system-ui, -apple-system, sans-serif;
    font-size: 14px;
    line-height: 1.5;
    color: var(--text-1);
    background: var(--bg);
    -webkit-font-smoothing: antialiased;
}

/* ── App Shell ─────────────────────────────────────────── */
.app {
    display: flex;
    height: 100vh;
    overflow: hidden;
}

/* ── Sidebar ───────────────────────────────────────────── */
.sidebar {
    width: 260px;
    min-width: 260px;
    background: var(--sidebar-bg);
    border-right: 1px solid var(--border);
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

/* Header */
.sidebar-header {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 14px 12px 12px;
    border-bottom: 1px solid var(--border);
    background: var(--bg);
}

.logo {
    display: flex;
    align-items: center;
    gap: 8px;
    flex: 1;
}

.logo-icon {
    width: 28px;
    height: 28px;
    background: var(--accent);
    color: #fff;
    border-radius: 7px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 14px;
    font-weight: 800;
    letter-spacing: -1px;
}

.logo-text  { font-size: 15px; font-weight: 700; color: var(--text-1); }
.logo-accent{ color: var(--accent); }

.new-chat-btn {
    display: inline-flex;
    align-items: center;
    gap: 5px;
    background: var(--accent);
    color: #fff;
    border: none;
    border-radius: 7px;
    padding: 6px 11px;
    font-size: 12px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: var(--transition);
    white-space: nowrap;
}
.new-chat-btn:hover { background: var(--accent-hover); }

/* ── Conversation List ─────────────────────────────────── */
.conv-list {
    flex: 1;
    overflow-y: auto;
    padding: 6px 0;
}
.conv-list::-webkit-scrollbar { width: 3px; }
.conv-list::-webkit-scrollbar-thumb { background: var(--border-2); border-radius: 2px; }

.conv-group-label {
    font-size: 10.5px;
    font-weight: 700;
    color: var(--text-3);
    text-transform: uppercase;
    letter-spacing: .06em;
    padding: 10px 14px 3px;
}

.conv-item {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 7px 12px;
    margin: 1px 6px;
    border-radius: 7px;
    cursor: pointer;
    transition: background .1s;
    position: relative;
    border-left: 2px solid transparent;
}
.conv-item:hover             { background: var(--sidebar-hover); }
.conv-item.active            { background: var(--sidebar-active); border-left-color: var(--accent); }

.conv-icon {
    color: var(--text-3);
    flex-shrink: 0;
}
.conv-item.active .conv-icon { color: var(--accent); }

.conv-title {
    flex: 1;
    font-size: 13px;
    color: var(--text-1);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}
.conv-item.active .conv-title { font-weight: 600; }

.conv-delete {
    display: none;
    align-items: center;
    justify-content: center;
    background: none;
    border: none;
    color: var(--text-3);
    cursor: pointer;
    padding: 3px;
    border-radius: 4px;
    flex-shrink: 0;
    transition: var(--transition);
}
.conv-item:hover .conv-delete  { display: flex; }
.conv-delete:hover             { background: var(--border); color: var(--red); }

.conv-empty {
    text-align: center;
    color: var(--text-3);
    font-size: 12px;
    padding: 24px 16px;
    line-height: 1.6;
}

/* ── Knowledge Base Section ───────────────────────────── */
.sidebar-knowledge {
    border-top: 1px solid var(--border);
}

.knowledge-toggle {
    width: 100%;
    display: flex;
    align-items: center;
    gap: 7px;
    padding: 11px 14px;
    background: none;
    border: none;
    font-family: inherit;
    font-size: 12.5px;
    font-weight: 600;
    color: var(--text-2);
    cursor: pointer;
    transition: color .15s;
}
.knowledge-toggle:hover        { color: var(--accent); }
.knowledge-toggle .arrow       { margin-left: auto; transition: transform .2s; }
.knowledge-toggle.open .arrow  { transform: rotate(180deg); }

.knowledge-body                { padding: 0 10px 12px; display: none; }
.knowledge-body.open           { display: block; }

/* Drop zone */
.drop-zone {
    border: 1.5px dashed var(--border-2);
    border-radius: 8px;
    padding: 14px 10px;
    text-align: center;
    cursor: pointer;
    transition: var(--transition);
}
.drop-zone:hover, .drop-zone.drag-over {
    border-color: var(--accent);
    background: var(--accent-dim);
}
.drop-zone input { display: none; }

.drop-icon-sm { font-size: 18px; margin-bottom: 4px; color: var(--text-3); }
.drop-label   { font-size: 11.5px; font-weight: 600; color: var(--text-2); }
.drop-sub     { font-size: 10.5px; color: var(--text-3); margin-top: 2px; }

/* Progress */
.progress-bar-wrap  { margin: 8px 0 2px; }
.progress-bar-bg    { height: 3px; background: var(--border); border-radius: 2px; }
.progress-fill      { height: 100%; background: var(--accent); border-radius: 2px; width: 0; transition: width .2s; }
.progress-label     { font-size: 10.5px; color: var(--text-3); display: block; margin-top: 3px; }

/* File list */
.file-list-sm       { list-style: none; margin-top: 8px; max-height: 100px; overflow-y: auto; }
.file-item-sm {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 11px;
    color: var(--text-2);
    padding: 4px 2px;
    border-bottom: 1px solid var(--border);
}
.file-item-sm:last-child { border-bottom: none; }

/* ── Main Chat Area ────────────────────────────────────── */
.main {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    background: var(--bg);
}

/* ── Messages ─────────────────────────────────────────── */
.messages {
    flex: 1;
    overflow-y: auto;
    padding: 24px 0 8px;
    display: flex;
    flex-direction: column;
    gap: 2px;
}
.messages::-webkit-scrollbar       { width: 5px; }
.messages::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }

/* Message row */
.message {
    display: flex;
    align-items: flex-start;
    gap: 12px;
    padding: 6px 28px;
}
.message-user { flex-direction: row-reverse; }

/* Avatar */
.avatar {
    width: 32px;
    height: 32px;
    min-width: 32px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 11px;
    font-weight: 700;
    flex-shrink: 0;
}
.bot-avatar  { background: var(--accent); color: #fff; }
.user-avatar { background: #e5e7eb; color: var(--text-2); border: 1px solid var(--border-2); }

/* Bubble */
.message-content {
    max-width: 680px;
    padding: 12px 16px;
    line-height: 1.75;
    word-break: break-word;
    font-size: 14px;
    border-radius: 16px;
}
.message-bot  .message-content {
    background: var(--bot-bg);
    border-bottom-left-radius: 4px;
    color: var(--text-1);
}
.message-user .message-content {
    background: var(--user-bg);
    border: 1px solid var(--user-border);
    border-bottom-right-radius: 4px;
    color: var(--text-1);
}

/* Typing dots */
.dots         { display: flex; gap: 5px; padding: 2px 0; }
.dots span    { width: 7px; height: 7px; background: var(--text-3); border-radius: 50%; animation: bounce 1.2s infinite; }
.dots span:nth-child(2) { animation-delay: .2s; }
.dots span:nth-child(3) { animation-delay: .4s; }
@keyframes bounce {
    0%, 60%, 100% { transform: translateY(0); }
    30%            { transform: translateY(-7px); }
}

/* Markdown inside messages */
.message-content p         { margin: 0 0 10px; }
.message-content p:last-child { margin: 0; }
.message-content h1,
.message-content h2,
.message-content h3        { margin: 14px 0 6px; font-weight: 700; line-height: 1.3; }
.message-content h1        { font-size: 18px; }
.message-content h2        { font-size: 16px; }
.message-content h3        { font-size: 14px; }
.message-content strong    { font-weight: 600; }
.message-content em        { font-style: italic; }
.message-content code      {
    font-family: 'JetBrains Mono', monospace;
    font-size: 12.5px;
    background: rgba(0,0,0,.06);
    padding: 1px 5px;
    border-radius: 4px;
}
.message-content pre       {
    background: #1e1e2e;
    color: #cdd6f4;
    padding: 14px 16px;
    border-radius: 8px;
    overflow-x: auto;
    margin: 10px 0;
}
.message-content pre code  { background: none; color: inherit; padding: 0; font-size: 13px; }
.message-content ul,
.message-content ol        { margin: 8px 0 8px 20px; }
.message-content li        { margin-bottom: 4px; }
.message-content blockquote{
    border-left: 3px solid var(--accent);
    margin: 10px 0;
    padding: 6px 12px;
    background: var(--accent-dim);
    border-radius: 0 6px 6px 0;
    color: var(--text-2);
}

/* ── Welcome Card ─────────────────────────────────────── */
.welcome-card {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    text-align: center;
    padding: 40px 32px;
    max-width: 620px;
    margin: 0 auto;
    width: 100%;
    gap: 12px;
}

.welcome-icon {
    width: 58px;
    height: 58px;
    background: var(--accent-dim);
    border: 1px solid var(--accent-border);
    border-radius: 14px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--accent);
    margin-bottom: 6px;
}

.welcome-title {
    font-size: 24px;
    font-weight: 700;
    letter-spacing: -.4px;
    color: var(--text-1);
}

.welcome-sub {
    font-size: 14.5px;
    color: var(--text-2);
    line-height: 1.7;
    max-width: 460px;
}
.welcome-sub strong { color: var(--accent); font-weight: 600; }

.welcome-chips {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    justify-content: center;
    margin-top: 10px;
}

.chip {
    background: var(--sidebar-bg);
    border: 1px solid var(--border);
    color: var(--text-2);
    font-size: 13px;
    font-weight: 500;
    padding: 8px 16px;
    border-radius: 20px;
    cursor: pointer;
    transition: var(--transition);
    font-family: inherit;
    user-select: none;
}
.chip:hover { background: var(--accent-dim); border-color: var(--accent-border); color: var(--accent); }

/* Welcome card header + inline rename controls */
.welcome-header { width: 100%; display: flex; justify-content: center; }
.welcome-title-row { display: flex; align-items: center; gap: 10px; }

.icon-btn {
    background: none;
    border: none;
    padding: 6px;
    border-radius: 8px;
    cursor: pointer;
    color: var(--text-3);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    transition: var(--transition);
}
.icon-btn svg { display: block; }
.icon-btn:hover { background: rgba(0,0,0,0.03); color: var(--accent); }

.welcome-title-edit {
    display: flex;
    gap: 8px;
    margin-top: 10px;
    align-items: center;
    justify-content: center;
}
.welcome-title-edit input {
    padding: 8px 10px;
    border-radius: 8px;
    border: 1px solid var(--border);
    min-width: 220px;
    font-size: 14px;
    outline: none;
}
.welcome-title-edit input:focus { box-shadow: var(--shadow-sm); border-color: var(--accent); }
.welcome-title-edit button {
    padding: 8px 10px;
    border-radius: 8px;
    border: none;
    cursor: pointer;
    font-weight: 600;
    font-family: inherit;
}
.welcome-title-edit #cardSaveTitleBtn { background: var(--accent); color: #fff; }
.welcome-title-edit #cardCancelTitleBtn { background: transparent; color: var(--text-2); border: 1px solid var(--border); }

/* ensure title doesn't overflow on small widths */
#welcome .welcome-title, .welcome-title { max-width: 420px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }

/* ── Input Area ───────────────────────────────────────── */
.input-area {
    padding: 14px 28px 18px;
    border-top: 1px solid var(--border);
    background: var(--bg);
}

.input-box {
    display: flex;
    align-items: flex-end;
    gap: 8px;
    border: 1.5px solid var(--border-2);
    border-radius: 13px;
    padding: 8px 8px 8px 12px;
    background: var(--bg);
    transition: border-color .15s, box-shadow .15s;
}
.input-box:focus-within {
    border-color: var(--accent);
    box-shadow: 0 0 0 3px rgba(255,124,29,.08);
}

.attach-btn {
    background: none;
    border: none;
    color: var(--text-3);
    cursor: pointer;
    padding: 5px 6px;
    border-radius: 7px;
    display: flex;
    align-items: center;
    transition: var(--transition);
    flex-shrink: 0;
}
.attach-btn:hover { background: var(--sidebar-bg); color: var(--accent); }

.message-input {
    flex: 1;
    border: none;
    outline: none;
    resize: none;
    font-family: inherit;
    font-size: 14px;
    color: var(--text-1);
    background: transparent;
    max-height: 150px;
    line-height: 1.6;
    padding: 5px 0;
}
.message-input::placeholder { color: var(--text-3); }

.send-btn {
    width: 34px;
    height: 34px;
    min-width: 34px;
    background: var(--accent);
    border: none;
    border-radius: 9px;
    color: #fff;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background .15s;
    flex-shrink: 0;
}
.send-btn:hover    { background: var(--accent-hover); }
.send-btn:disabled { background: var(--border-2); cursor: not-allowed; }

.input-hint {
    font-size: 11px;
    color: var(--text-3);
    margin-top: 7px;
    text-align: center;
}
.input-hint kbd {
    background: #f0f0f0;
    border: 1px solid var(--border-2);
    border-radius: 3px;
    padding: 1px 5px;
    font-size: 10px;
    font-family: monospace;
}

/* ── Toast ────────────────────────────────────────────── */
.toast {
    position: fixed;
    bottom: 24px;
    right: 24px;
    padding: 10px 18px;
    border-radius: 8px;
    font-size: 13px;
    font-weight: 500;
    z-index: 9999;
    opacity: 0;
    pointer-events: none;
    transform: translateY(8px);
    transition: all .2s;
    max-width: 320px;
}
.toast.show       { opacity: 1; transform: translateY(0); pointer-events: auto; }
.toast-success    { background: #16a34a; color: #fff; }
.toast-error      { background: #dc2626; color: #fff; }
.toast-default    { background: var(--text-1); color: #fff; }

/* ── Code Blocks ──────────────────────────────────────── */
/* Code block wrapper + toolbar for expand/copy and resizable blocks */
.code-wrap {
    position: relative;
    margin: 10px 0;
}
.code-wrap .code-toolbar {
    position: absolute;
    top: 8px;
    right: 8px;
    display: flex;
    gap: 6px;
    z-index: 6;
}
.code-btn {
    background: rgba(255,255,255,0.06);
    border: 1px solid rgba(255,255,255,0.06);
    color: #cdd6f4;
    padding: 4px 8px;
    border-radius: 6px;
    font-size: 12px;
    cursor: pointer;
    backdrop-filter: blur(2px);
}
.code-btn:hover { background: rgba(255,255,255,0.10); }

/* Toolbar copy button styling and tooltip (uses data-tooltip attr) */
.code-btn.code-copy-btn {
    background: rgba(0,0,0,0.28);
    border: none;
    color: #fff;
    padding: 8px;
    border-radius: 8px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    transition: background .12s ease, transform .12s ease;
}
.code-btn.code-copy-btn svg { opacity: 0.95; }
.code-btn.code-copy-btn:hover { background: rgba(0,0,0,0.42); transform: translateY(-2px); }
.code-btn.code-copy-btn.copied { background: #10b981; box-shadow: 0 8px 22px rgba(16,185,129,0.18); }

/* data-tooltip pseudo element for small hover label */
.code-btn[data-tooltip] {
    position: relative;
}
.code-btn[data-tooltip]::after {
    content: attr(data-tooltip);
    position: absolute;
    top: -36px;
    right: 0;
    transform: translateY(6px);
    background: rgba(17,24,39,0.95);
    color: #fff;
    padding: 6px 8px;
    border-radius: 6px;
    font-size: 12px;
    opacity: 0;
    pointer-events: none;
    transition: opacity .12s, transform .12s;
    white-space: nowrap;
}
.code-btn[data-tooltip]:hover::after { opacity: 1; transform: translateY(0); }

/* Smooth overlay open/close */
.code-wrap {
    transition: transform .18s cubic-bezier(.2,.9,.3,1), box-shadow .18s;
}
.code-wrap.expanded {
    transform: scale(1.01);
}
.code-wrap.expanded { animation: overlayIn .14s ease; }
@keyframes overlayIn { from { opacity: 0; transform: translateY(6px) scale(.998); } to { opacity: 1; transform: translateY(0) scale(1); } }

/* Ensure toolbar sits above pre content */
.code-toolbar { z-index: 12; }

/* Expanded overlay mode */
.code-wrap.expanded {
    position: fixed;
    top: 5vh;
    left: 5vw;
    right: 5vw;
    bottom: 5vh;
    z-index: 9999;
    display: flex;
    flex-direction: column;
    background: rgba(17,20,26,0.96);
    padding: 12px;
    border-radius: 10px;
    box-shadow: 0 10px 40px rgba(2,6,23,0.6);
}
.code-wrap.expanded pre {
    flex: 1 1 auto;
    width: 100% !important;
    height: 100% !important;
    max-height: none !important;
    overflow: auto !important;
}

/* Ensure code-wrap can expand wider than the message bubble but not exceed viewport */
.message-content .code-wrap {
    width: auto;
    max-width: 90vw; /* allow horizontal expansion up to viewport */
}
.message-content .code-wrap pre {
    width: 100%;
    box-sizing: border-box;
    white-space: pre; /* preserve whitespace; prevents forced wrapping inside code by default */
}

/* Ensure pre remains visually distinct and can be resized when not expanded */
.message-content pre {
    resize: both;
    min-width: 220px;
    min-height: 80px;
}

/* Floating copy button (right-middle) */
.code-copy-float {
    position: absolute;
    top: 12px;
    right: 12px;
    background: rgba(0,0,0,0.48);
    border: none;
    color: #fff;
    padding: 8px;
    width: 40px;
    height: 40px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border-radius: 8px;
    cursor: pointer;
    transition: transform .12s ease, background .12s ease, box-shadow .12s ease;
    z-index: 8;
    box-shadow: 0 6px 18px rgba(2,6,23,0.45);
}
.code-copy-float svg { opacity: 0.95; }
.code-copy-float:hover { transform: translateY(-3px); background: rgba(0,0,0,0.62); }
.code-copy-float.copied { background: #10b981; transform: scale(1.05); box-shadow: 0 8px 22px rgba(16,185,129,0.18); }

/* When overlay expanded, move floating button to top-right and adjust color to match dark overlay */
.code-wrap.expanded .code-copy-float {
    top: 12px;
    right: 16px;
    background: rgba(255,255,255,0.06);
    color: #cdd6f4;
}

/* Slightly reduce toolbar size so copy float is primary control */
.code-toolbar { opacity: 0.95; }
.code-toolbar .code-btn { padding: 6px; width: 36px; height: 36px; display: inline-flex; align-items: center; justify-content: center; }

/* Ensure code-wrap has a subtle border when not expanded to separate from background */
.code-wrap { outline: 1px solid rgba(0,0,0,0.04); }

/* ── Responsive ───────────────────────────────────────── */
@media (max-width: 640px) {
    .sidebar         { display: none; }
    .message         { padding: 4px 14px; }
    .input-area      { padding: 12px 14px 16px; }
    .welcome-title   { font-size: 20px; }
}

'use strict';

/* ═══════════════════════════════════════════════════════
   SESSION STORAGE (server-backed)
   Previously used localStorage metadata only. Now load sessions
   from the backend /api/sessions and treat the server as source
   of truth. Keep small local fallback when there are no sessions.
   ═══════════════════════════════════════════════════════ */
let sessions = []; // server-provided list: {id, title, messageCount, ...}

async function loadSessionsFromServer() {
    try {
        const res = await fetch('/api/sessions');
        if (!res.ok) throw new Error('Failed to load sessions');
        const data = await res.json();
        sessions = data || [];
        // if current session exists in server list, update its title
        if (currentSession) {
            const found = sessions.find(s => s.id === currentSession.id);
            if (found) {
                currentSession.title = found.title || currentSession.title;
                if (sessionTitleEl) sessionTitleEl.textContent = currentSession.title;
            }
        }
    } catch (e) {
        // fallback: keep existing sessions array (can be empty)
        console.warn('Could not load sessions from server:', e);
        sessions = sessions || [];
    }
}

function createLocalSession() {
    const s = {
        id: crypto.randomUUID(),
        title: 'New Conversation',
        createdAt: new Date().toISOString()
    };
    sessions.unshift(s);
    return s;
}

/* ═══════════════════════════════════════════════════════
   STATE
   ═══════════════════════════════════════════════════════ */
let currentSession = null;
let isSending = false;

/* ═══════════════════════════════════════════════════════
   DOM REFERENCES
   ═══════════════════════════════════════════════════════ */
const messagesEl    = document.getElementById('messages');
const messageInput  = document.getElementById('messageInput');
const sendBtn       = document.getElementById('sendBtn');
const convListEl    = document.getElementById('convList');
const dropZone      = document.getElementById('dropZone');
const fileInput     = document.getElementById('fileInput');
const progressWrap  = document.getElementById('progressBarWrap');
const progressFill  = document.getElementById('progressFill');
const progressLabel = document.getElementById('progressLabel');
const fileListEl    = document.getElementById('fileList');
const uploadTrigger = document.getElementById('uploadTrigger');

// New: chat header elements for rename
const sessionTitleEl = document.getElementById('sessionTitle');
const editTitleBtn   = document.getElementById('editTitleBtn');
const chatTitleEdit  = document.getElementById('chatTitleEdit');
const titleInput     = document.getElementById('titleInput');
const saveTitleBtn   = document.getElementById('saveTitleBtn');
const cancelTitleBtn = document.getElementById('cancelTitleBtn');

/* ═══════════════════════════════════════════════════════
   INIT
   ═══════════════════════════════════════════════════════ */
async function init() {
    // Load sessions for the sidebar but do not auto-open an existing session — start a fresh chat like ChatGPT
    await loadSessionsFromServer();

    // Start with a new conversation view
    currentSession = createLocalSession();
    renderSidebar();
    clearMessages();
    showWelcomeCard();
    messageInput.focus();

    // initialize header title
    if (sessionTitleEl) sessionTitleEl.textContent = currentSession.title || 'New Conversation';

    // wire rename UI
    if (editTitleBtn) editTitleBtn.addEventListener('click', () => {
        if (!chatTitleEdit || !titleInput) return;
        titleInput.value = currentSession ? (currentSession.title || '') : '';
        chatTitleEdit.style.display = 'flex';
        titleInput.focus();
    });
    if (cancelTitleBtn) cancelTitleBtn.addEventListener('click', () => {
        if (!chatTitleEdit) return; chatTitleEdit.style.display = 'none';
    });
    if (saveTitleBtn) saveTitleBtn.addEventListener('click', async () => {
        if (!titleInput) return;
        const newTitle = titleInput.value.trim();
        if (!currentSession) return;
        // call backend rename endpoint if possible
        try {
            const res = await fetch(`/api/sessions/${currentSession.id}/rename`, {
                method: 'PUT', headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ title: newTitle })
            });
            if (res.ok) {
                const data = await res.json();
                currentSession.title = data.title || newTitle || 'New Conversation';
                // update sessions array if we have it
                const idx = sessions.findIndex(s => s.id === currentSession.id);
                if (idx >= 0) sessions[idx].title = currentSession.title;
                // update UI
                if (sessionTitleEl) sessionTitleEl.textContent = currentSession.title;
                renderSidebar();
                showToast('Conversation renamed', 'success');
            } else {
                showToast('Rename failed', 'error');
            }
        } catch (e) {
            // offline/local mode: update only locally
            currentSession.title = newTitle || 'New Conversation';
            const idx = sessions.findIndex(s => s.id === currentSession.id);
            if (idx >= 0) sessions[idx].title = currentSession.title;
            if (sessionTitleEl) sessionTitleEl.textContent = currentSession.title;
            renderSidebar();
            showToast('Renamed locally (offline)', 'default');
        } finally {
            if (chatTitleEdit) chatTitleEdit.style.display = 'none';
        }
    });
}

/* ═══════════════════════════════════════════════════════
   SIDEBAR
   ═══════════════════════════════════════════════════════ */
function relativeGroup(isoStr) {
    const now   = new Date();
    const d     = new Date(isoStr);
    const diffD = Math.floor((now - d) / 86400000);
    if (diffD === 0) return 'Today';
    if (diffD === 1) return 'Yesterday';
    if (diffD <= 7) return 'Previous 7 Days';
    return 'Older';
}

function renderSidebar() {
    if (!sessions || sessions.length === 0) {
        convListEl.innerHTML = `
            <div class="conv-empty">
                No conversations yet.<br>
                Hit <strong>New</strong> to start one.
            </div>`;
        return;
    }

    const groupOrder = ['Today', 'Yesterday', 'Previous 7 Days', 'Older'];
    const groups = {};
    sessions.forEach(s => {
        // ensure createdAt exists for grouping; fallback to now
        const created = s.createdAt || new Date().toISOString();
        const g = relativeGroup(created);
        (groups[g] = groups[g] || []).push(s);
    });

    let html = '';
    groupOrder.forEach(label => {
        if (!groups[label]) return;
        html += `<div class="conv-group-label">${label}</div>`;
        groups[label].forEach(s => {
            const active = currentSession && s.id === currentSession.id ? 'active' : '';
            const title = escapeHtml(s.title || 'New Conversation');
            html += `
            <div class="conv-item ${active}" onclick="switchSession('${s.id}')">
                <svg class="conv-icon" width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"></path>
                </svg>
                <span class="conv-title">${title}</span>
                <button class="conv-delete" onclick="event.stopPropagation();deleteConv('${s.id}')" title="Delete conversation">
                    <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">
                        <line x1="18" y1="6" x2="6" y2="18"></line>
                        <line x1="6" y1="6" x2="18" y2="18"></line>
                    </svg>
                </button>
            </div>`;
        });
    });
    convListEl.innerHTML = html;
}

/* ═══════════════════════════════════════════════════════
   KNOWLEDGE BASE TOGGLE
   ═══════════════════════════════════════════════════════ */
function toggleKnowledge(btn) {
    btn.classList.toggle('open');
    document.getElementById('knowledgeBody').classList.toggle('open');
}

/* ═══════════════════════════════════════════════════════
   CONVERSATION SWITCHING
   ═══════════════════════════════════════════════════════ */
async function switchSession(id) {
    if (currentSession && currentSession.id === id) return;
    const s = sessions.find(x => x.id === id);
    if (!s) {
        // try reloading sessions from server
        await loadSessionsFromServer();
        const found = sessions.find(x => x.id === id);
        if (!found) return;
        currentSession = found;
    } else {
        currentSession = s;
    }
    renderSidebar();
    clearMessages();
    // update header title when switching
    if (sessionTitleEl) sessionTitleEl.textContent = currentSession.title || 'New Conversation';
    await loadSessionMessages(id);
}

async function loadSessionMessages(sessionId) {
    try {
        const res  = await fetch(`/api/sessions/${sessionId}/messages`);
        const data = await res.json();
        const msgs = data.messages || [];
        if (msgs.length > 0) {
            msgs.forEach(m => {
                const role = (m.role || '').toLowerCase() === 'user' ? 'user' : 'bot';
                appendMessage(role, m.content, false);
            });
            messagesEl.scrollTop = messagesEl.scrollHeight;
            // typeset any LaTeX in the newly added messages
            if (window.MathJax && MathJax.typesetPromise) MathJax.typesetPromise();
        } else {
            showWelcomeCard();
        }
    } catch {
        showWelcomeCard();
    }
}

async function newChat() {
    // Request backend to clear current session and get a fresh session id
    try {
        const res = await fetch('/api/chat/clear', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ sessionId: currentSession ? currentSession.id : null })
        });
        const data = await res.json();
        const newId = data.sessionId || crypto.randomUUID();
        // insert locally so UI shows it immediately
        currentSession = { id: newId, title: 'New Conversation', createdAt: new Date().toISOString() };
        if (sessionTitleEl) sessionTitleEl.textContent = currentSession.title;
        sessions.unshift(currentSession);
        renderSidebar();
        clearMessages();
        showWelcomeCard();
        messageInput.focus();
    } catch (e) {
        // fallback to purely local new session
        currentSession = createLocalSession();
        if (sessionTitleEl) sessionTitleEl.textContent = currentSession.title;
        renderSidebar();
        clearMessages();
        showWelcomeCard();
        messageInput.focus();
    }
}

async function deleteConv(id) {
    if (!confirm('Delete this conversation? This cannot be undone.')) return;
    try { await fetch(`/api/sessions/${id}`, { method: 'DELETE' }); } catch { /* ok */ }

    // Refresh sessions from server
    await loadSessionsFromServer();

    // Update local sessions array and currentSession
    sessions = sessions.filter(s => s.id !== id);

    if (currentSession && currentSession.id === id) {
        if (sessions.length > 0) {
            currentSession = sessions[0];
            renderSidebar();
            clearMessages();
            await loadSessionMessages(currentSession.id);
        } else {
            currentSession = createLocalSession();
            renderSidebar();
            clearMessages();
            showWelcomeCard();
        }
    } else {
        renderSidebar();
    }
}

/* ═══════════════════════════════════════════════════════
   MESSAGES
   ═══════════════════════════════════════════════════════ */
function clearMessages() {
    messagesEl.innerHTML = '';
}

function showWelcomeCard() {
    messagesEl.innerHTML = `
    <div class="welcome-card">
        <div class="welcome-icon">
            <svg width="26" height="26" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8">
                <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"></path>
            </svg>
        </div>
        <h1 class="welcome-title">How can I help you?</h1>
        <p class="welcome-sub">
            I remember our conversations across sessions — tell me your name, upload documents, and ask anything.<br>
            History is saved in <strong>MySQL</strong> and survives restarts.
        </p>
        <div class="welcome-chips">
            <button class="chip" onclick="fillInput(this)">Summarize the document</button>
            <button class="chip" onclick="fillInput(this)">What are the key points?</button>
            <button class="chip" onclick="fillInput(this)">My name is...</button>
            <button class="chip" onclick="fillInput(this)">List all topics covered</button>
        </div>
    </div>`;
}

function fillInput(el) {
    const card = messagesEl.querySelector('.welcome-card');
    if (card) card.remove();
    messageInput.value = el.textContent;
    messageInput.focus();
    messageInput.dispatchEvent(new Event('input'));
}

function removeWelcomeCard() {
    const c = messagesEl.querySelector('.welcome-card');
    if (c) c.remove();
}

function appendMessage(role, text, scroll = true) {
    removeWelcomeCard();
    const isUser = role === 'user';
    const div = document.createElement('div');
    div.className = `message message-${isUser ? 'user' : 'bot'}`;
    div.innerHTML = `
        <div class="avatar ${isUser ? 'user-avatar' : 'bot-avatar'}">${isUser ? 'You' : 'AI'}</div>
        <div class="message-content">${formatMarkdown(text)}</div>`;
    messagesEl.appendChild(div);
    if (scroll) messagesEl.scrollTop = messagesEl.scrollHeight;

    // Syntax highlight any code blocks we just inserted
    if (window.hljs && hljs.highlightElement) {
        try {
            div.querySelectorAll('pre code').forEach(el => {
                try { hljs.highlightElement(el); } catch(e) { /* ignore */ }
            });
        } catch(e) { /* ignore */ }
    }

    // Add toolbar + expand/copy behavior to code blocks (allow vertical and horizontal resize/expand)
    try {
        div.querySelectorAll('pre code').forEach(codeEl => {
            if (codeEl.dataset.processed) return;
            codeEl.dataset.processed = '1';

            const pre = codeEl.closest('pre');
            // make pre resizable and scrollable
            pre.style.overflow = 'auto';
            pre.style.resize = 'both';
            pre.style.maxHeight = '60vh';

            // wrap pre in container to position toolbar
            const wrap = document.createElement('div');
            wrap.className = 'code-wrap';
            pre.parentNode.replaceChild(wrap, pre);
            wrap.appendChild(pre);

            // toolbar
            const toolbar = document.createElement('div');
            toolbar.className = 'code-toolbar';

            // Copy button placed in toolbar (icon + label on hover)
            const btnCopy = document.createElement('button');
            btnCopy.type = 'button';
            btnCopy.className = 'code-btn code-copy-btn';
            btnCopy.setAttribute('aria-label', 'Copy code');
            btnCopy.setAttribute('data-tooltip', 'Copy');
            btnCopy.innerHTML = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.6" style="vertical-align:middle"><rect x="9" y="9" width="10" height="10" rx="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg>';

            // Expand/Collapse button (small, top-right)
            const btnExpand = document.createElement('button');
            btnExpand.type = 'button';
            btnExpand.className = 'code-btn code-expand';
            btnExpand.setAttribute('aria-label', 'Expand code');
            btnExpand.innerHTML = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.6" style="vertical-align:middle"><polyline points="9 14 9 21 16 21"></polyline><polyline points="15 9 15 3 8 3"></polyline><polyline points="21 9 21 16 16 16"></polyline><polyline points="3 15 3 8 8 8"></polyline></svg>';

            toolbar.appendChild(btnCopy);
            toolbar.appendChild(btnExpand);
            wrap.appendChild(toolbar);

            // helper to open/close expanded state and manage body scroll
            const openExpanded = () => {
                wrap.classList.add('expanded');
                document.body.style.overflow = 'hidden';
                // ensure pre takes full space
                pre.style.height = '100%';
                pre.style.maxHeight = 'none';
                // listen for esc to close
                const onKey = (e) => { if (e.key === 'Escape') closeExpanded(); };
                document.addEventListener('keydown', onKey);
                wrap._onKey = onKey;
            };
            const closeExpanded = () => {
                wrap.classList.remove('expanded');
                document.body.style.overflow = '';
                pre.style.height = 'auto';
                pre.style.maxHeight = '60vh';
                if (wrap._onKey) document.removeEventListener('keydown', wrap._onKey);
            };

            // click outside (on overlay background) closes when expanded
            wrap.addEventListener('click', (ev) => {
                if (wrap.classList.contains('expanded') && ev.target === wrap) {
                    closeExpanded();
                }
            });

            // expand toggle
            btnExpand.addEventListener('click', () => {
                if (wrap.classList.contains('expanded')) closeExpanded(); else openExpanded();
            });

            // copy button behavior (with tooltip feedback)
            btnCopy.addEventListener('click', async () => {
                const showCopied = () => {
                    btnCopy.classList.add('copied');
                    btnCopy.setAttribute('data-tooltip', 'Copied');
                    setTimeout(() => { btnCopy.classList.remove('copied'); btnCopy.setAttribute('data-tooltip', 'Copy'); }, 1400);
                };
                try {
                    await navigator.clipboard.writeText(codeEl.textContent);
                    showCopied();
                    showToast('Code copied', 'success');
                } catch (e) {
                    try {
                        const ta = document.createElement('textarea');
                        ta.value = codeEl.textContent;
                        ta.style.position = 'absolute';
                        ta.style.left = '-9999px';
                        document.body.appendChild(ta);
                        ta.select();
                        document.execCommand('copy');
                        ta.remove();
                        showCopied();
                        showToast('Code copied', 'success');
                    } catch (err) {
                        showToast('Copy failed', 'error');
                    }
                }
            });

            // Auto-expand removed: code blocks should only expand when user clicks the expand button
        });
    } catch (e) { /* ignore */ }

    // Render LaTeX (MathJax) for dynamic content
    if (window.MathJax && MathJax.typesetPromise) {
        try { MathJax.typesetPromise([div]); }
        catch (e) { /* ignore MathJax errors */ }
    }
}

function showTyping() {
    removeWelcomeCard();
    const div = document.createElement('div');
    div.id = 'typing';
    div.className = 'message message-bot';
    div.innerHTML = `
        <div class="avatar bot-avatar">AI</div>
        <div class="message-content"><div class="dots">
            <span></span><span></span><span></span>
        </div></div>`;
    messagesEl.appendChild(div);
    messagesEl.scrollTop = messagesEl.scrollHeight;
}

function removeTyping() {
    const t = document.getElementById('typing');
    if (t) t.remove();
}

/* ═══════════════════════════════════════════════════════
   MARKDOWN FORMATTER
   ═══════════════════════════════════════════════════════ */
function formatMarkdown(text) {
    // 1) Extract fenced code blocks and replace with placeholders
    const codeBlocks = [];
    const placeholder = (i) => `@@CODE_BLOCK_${i}@@`;
    text = text.replace(/```(\w*)\n?([\s\S]*?)```/g, (_, lang, code) => {
        const idx = codeBlocks.length;
        codeBlocks.push({ lang: lang || '', code: code });
        return placeholder(idx);
    });

    // 2) Escape the rest of the text
    let s = escapeHtml(text);

    // 3) Inline code (keep as HTML <code>)
    s = s.replace(/`([^`\n]+)`/g, '<code>$1</code>');

    // 4) Bold & italic
    s = s.replace(/\*\*\*(.*?)\*\*\*/g, '<strong><em>$1</em></strong>');
    s = s.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
    s = s.replace(/\*(.*?)\*/g, '<em>$1</em>');

    // 5) Headers
    s = s.replace(/^### (.*)/gm, '<h3>$1</h3>');
    s = s.replace(/^## (.*)/gm,  '<h2>$1</h2>');
    s = s.replace(/^# (.*)/gm,   '<h1>$1</h1>');

    // 6) Blockquote
    s = s.replace(/^&gt; (.*)/gm, '<blockquote>$1</blockquote>');

    // 7) Bullet lists
    s = s.replace(/^[-*] (.*)/gm, '<li>$1</li>');
    s = s.replace(/(<li>.*?<\/li>)(\n<li>)/gs, '$1$2');
    s = s.replace(/(<li>[\s\S]*?<\/li>)/g, '<ul>$1</ul>');

    // 8) Paragraphs and remaining newlines: convert double newlines to paragraph breaks, single newlines to <br>
    s = s.replace(/\n\n+/g, '</p><p>');
    s = s.replace(/\n/g, '<br>');

    // 9) Wrap in paragraph if not starting with block element
    if (!s.match(/^<(h[1-6]|ul|ol|pre|blockquote)/)) {
        s = '<p>' + s + '</p>';
    }

    // 10) Restore code blocks placeholders with properly escaped content (preserve newlines inside <pre>)
    codeBlocks.forEach((cb, i) => {
        // normalize newlines and attempt to fix adjacent includes that got concatenated
        let raw = cb.code.replace(/\r\n/g, '\n');
        // Insert newline between adjacent #include occurrences if they were concatenated
        raw = raw.replace(/(#include\s*(?:<[^>]+>|"[^"]+")?)(?=#include)/g, '$1\n');
        // Ensure comments are intact (no trimming) - keep raw as-is
        const safeCode = escapeHtml(raw);
        const langClass = cb.lang ? ` class="language-${cb.lang}"` : '';
        s = s.replace(placeholder(i), `<pre><code${langClass}>${safeCode}</code></pre>`);
    });

    return s;
}

function escapeHtml(s) {
    return String(s)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
}

/* ═══════════════════════════════════════════════════════
   SEND MESSAGE
   ═══════════════════════════════════════════════════════ */
async function sendMessage() {
    const text = messageInput.value.trim();
    if (!text || isSending) return;

    if (!currentSession) {
        currentSession = createLocalSession();
        renderSidebar();
    }

    isSending = true;
    appendMessage('user', text);
    messageInput.value = '';
    messageInput.style.height = 'auto';
    sendBtn.disabled = true;
    showTyping();

    try {
        const res  = await fetch('/api/chat', {
            method:  'POST',
            headers: { 'Content-Type': 'application/json' },
            body:    JSON.stringify({ message: text, sessionId: currentSession.id })
        });
        const data = await res.json();
        removeTyping();

        if (res.ok) {
            appendMessage('bot', data.response);
            // Ensure LaTeX in bot response renders
            if (window.MathJax && MathJax.typesetPromise) MathJax.typesetPromise();

            // After saving message on server, refresh sessions so titles/counts update
            await loadSessionsFromServer();
            const updated = sessions.find(s => s.id === currentSession.id);
            if (updated) currentSession.title = updated.title || currentSession.title;
            renderSidebar();
        } else {
            appendMessage('bot', '⚠️ ' + (data.error || 'Something went wrong.'));
            if (window.MathJax && MathJax.typesetPromise) MathJax.typesetPromise();
        }
    } catch {
        removeTyping();
        appendMessage('bot', '⚠️ Cannot reach the server. Is the backend running?');
        if (window.MathJax && MathJax.typesetPromise) MathJax.typesetPromise();
    } finally {
        isSending = false;
        sendBtn.disabled = false;
        messageInput.focus();
    }
}

/* Input events */
sendBtn.addEventListener('click', sendMessage);
messageInput.addEventListener('keydown', e => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(); }
});
messageInput.addEventListener('input', () => {
    messageInput.style.height = 'auto';
    messageInput.style.height = Math.min(messageInput.scrollHeight, 150) + 'px';
});

/* ═══════════════════════════════════════════════════════
   TOAST
   ═══════════════════════════════════════════════════════ */
let _toastTimer;
function showToast(msg, type = 'default') {
    let t = document.getElementById('toast');
    if (!t) { t = document.createElement('div'); t.id = 'toast'; document.body.appendChild(t); }
    clearTimeout(_toastTimer);
    t.textContent = msg;
    t.className = `toast toast-${type}`;
    t.getBoundingClientRect();
    t.classList.add('show');
    _toastTimer = setTimeout(() => t.classList.remove('show'), 3200);
}

/* ═══════════════════════════════════════════════════════
   FILE UPLOAD
   ═══════════════════════════════════════════════════════ */
uploadTrigger.addEventListener('click', () => {
    // Open knowledge base section and trigger file picker
    const body   = document.getElementById('knowledgeBody');
    const toggle = document.querySelector('.knowledge-toggle');
    if (!body.classList.contains('open')) {
        toggle.classList.add('open');
        body.classList.add('open');
    }
    fileInput.click();
});

dropZone.addEventListener('click', () => fileInput.click());
dropZone.addEventListener('dragover', e => { e.preventDefault(); dropZone.classList.add('drag-over'); });
dropZone.addEventListener('dragleave', () => dropZone.classList.remove('drag-over'));
dropZone.addEventListener('drop', async e => {
    e.preventDefault();
    dropZone.classList.remove('drag-over');
    for (const f of [...e.dataTransfer.files]) await uploadFile(f);
});
fileInput.addEventListener('change', async () => {
    for (const f of [...fileInput.files]) await uploadFile(f);
    fileInput.value = '';
});

async function uploadFile(file) {
    progressWrap.style.display = 'block';
    progressFill.style.width = '0%';
    progressLabel.textContent = `Uploading ${file.name}…`;

    let prog = 0;
    const ticker = setInterval(() => {
        prog = Math.min(prog + Math.random() * 14, 85);
        progressFill.style.width = prog + '%';
    }, 160);

    try {
        const fd  = new FormData();
        fd.append('file', file);
        const res  = await fetch('/api/upload', { method: 'POST', body: fd });
        const data = await res.json();
        clearInterval(ticker);
        progressFill.style.width = '100%';

        if (res.ok) {
            progressLabel.textContent = '✓ ' + data.message;
            addFileToList(file.name);
            showToast('✓ Indexed: ' + file.name, 'success');
        } else {
            progressLabel.textContent = '✗ ' + (data.error || 'Upload failed');
            showToast('✗ ' + (data.error || 'Upload failed'), 'error');
        }
    } catch {
        clearInterval(ticker);
        progressLabel.textContent = '✗ Connection error';
        showToast('✗ Upload error', 'error');
    } finally {
        setTimeout(() => { progressWrap.style.display = 'none'; }, 3000);
    }
}

function addFileToList(name) {
    const li = document.createElement('li');
    li.className = 'file-item-sm';
    li.innerHTML = `<span style="color:var(--green)">✓</span>${escapeHtml(name)}`;
    fileListEl.appendChild(li);
}

/* ═══════════════════════════════════════════════════════
   START
   ═══════════════════════════════════════════════════════ */
init();

'use strict';

/* ═══════════════════════════════════════════════════════
   SESSION STORAGE (server-backed)
   Previously used localStorage metadata only. Now load sessions
   from the backend /api/sessions and treat the server as source
   of truth. Keep small local fallback when there are no sessions.
   ═══════════════════════════════════════════════════════ */
let sessions = []; // server-provided list: {id, title, messageCount, ...}

async function loadSessionsFromServer() {
    try {
        const res = await fetch('/api/sessions');
        if (!res.ok) throw new Error('Failed to load sessions');
        const data = await res.json();
        sessions = data || [];
        // if current session exists in server list, update its title
        if (currentSession) {
            const found = sessions.find(s => s.id === currentSession.id);
            if (found) {
                currentSession.title = found.title || currentSession.title;
                if (sessionTitleEl) sessionTitleEl.textContent = currentSession.title;
            }
        }
    } catch (e) {
        // fallback: keep existing sessions array (can be empty)
        console.warn('Could not load sessions from server:', e);
        sessions = sessions || [];
    }
}

function createLocalSession() {
    const s = {
        id: crypto.randomUUID(),
        title: 'New Conversation',
        createdAt: new Date().toISOString()
    };
    sessions.unshift(s);
    return s;
}

/* ═══════════════════════════════════════════════════════
   STATE
   ═══════════════════════════════════════════════════════ */
let currentSession = null;
let isSending = false;

/* ═══════════════════════════════════════════════════════
   DOM REFERENCES
   ═══════════════════════════════════════════════════════ */
const messagesEl    = document.getElementById('messages');
const messageInput  = document.getElementById('messageInput');
const sendBtn       = document.getElementById('sendBtn');
const convListEl    = document.getElementById('convList');
const dropZone      = document.getElementById('dropZone');
const fileInput     = document.getElementById('fileInput');
const progressWrap  = document.getElementById('progressBarWrap');
const progressFill  = document.getElementById('progressFill');
const progressLabel = document.getElementById('progressLabel');
const fileListEl    = document.getElementById('fileList');
const uploadTrigger = document.getElementById('uploadTrigger');

// New: chat header elements for rename
const sessionTitleEl = document.getElementById('sessionTitle');
const editTitleBtn   = document.getElementById('editTitleBtn');
const chatTitleEdit  = document.getElementById('chatTitleEdit');
const titleInput     = document.getElementById('titleInput');
const saveTitleBtn   = document.getElementById('saveTitleBtn');
const cancelTitleBtn = document.getElementById('cancelTitleBtn');

/* ═══════════════════════════════════════════════════════
   INIT
   ═══════════════════════════════════════════════════════ */
async function init() {
    // Load sessions for the sidebar but do not auto-open an existing session — start a fresh chat like ChatGPT
    await loadSessionsFromServer();

    // Start with a new conversation view
    currentSession = createLocalSession();
    renderSidebar();
    clearMessages();
    showWelcomeCard();
    messageInput.focus();

    // initialize header title
    if (sessionTitleEl) sessionTitleEl.textContent = currentSession.title || 'New Conversation';

    // wire rename UI
    if (editTitleBtn) editTitleBtn.addEventListener('click', () => {
        if (!chatTitleEdit || !titleInput) return;
        titleInput.value = currentSession ? (currentSession.title || '') : '';
        chatTitleEdit.style.display = 'flex';
        titleInput.focus();
    });
    if (cancelTitleBtn) cancelTitleBtn.addEventListener('click', () => {
        if (!chatTitleEdit) return; chatTitleEdit.style.display = 'none';
    });
    if (saveTitleBtn) saveTitleBtn.addEventListener('click', async () => {
        if (!titleInput) return;
        const newTitle = titleInput.value.trim();
        if (!currentSession) return;
        // call backend rename endpoint if possible
        try {
            const res = await fetch(`/api/sessions/${currentSession.id}/rename`, {
                method: 'PUT', headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ title: newTitle })
            });
            if (res.ok) {
                const data = await res.json();
                currentSession.title = data.title || newTitle || 'New Conversation';
                // update sessions array if we have it
                const idx = sessions.findIndex(s => s.id === currentSession.id);
                if (idx >= 0) sessions[idx].title = currentSession.title;
                // update UI
                if (sessionTitleEl) sessionTitleEl.textContent = currentSession.title;
                renderSidebar();
                showToast('Conversation renamed', 'success');
            } else {
                showToast('Rename failed', 'error');
            }
        } catch (e) {
            // offline/local mode: update only locally
            currentSession.title = newTitle || 'New Conversation';
            const idx = sessions.findIndex(s => s.id === currentSession.id);
            if (idx >= 0) sessions[idx].title = currentSession.title;
            if (sessionTitleEl) sessionTitleEl.textContent = currentSession.title;
            renderSidebar();
            showToast('Renamed locally (offline)', 'default');
        } finally {
            if (chatTitleEdit) chatTitleEdit.style.display = 'none';
        }
    });
}

/* ═══════════════════════════════════════════════════════
   SIDEBAR
   ═══════════════════════════════════════════════════════ */
function relativeGroup(isoStr) {
    const now   = new Date();
    const d     = new Date(isoStr);
    const diffD = Math.floor((now - d) / 86400000);
    if (diffD === 0) return 'Today';
    if (diffD === 1) return 'Yesterday';
    if (diffD <= 7) return 'Previous 7 Days';
    return 'Older';
}

function renderSidebar() {
    if (!sessions || sessions.length === 0) {
        convListEl.innerHTML = `
            <div class="conv-empty">
                No conversations yet.<br>
                Hit <strong>New</strong> to start one.
            </div>`;
        return;
    }

    const groupOrder = ['Today', 'Yesterday', 'Previous 7 Days', 'Older'];
    const groups = {};
    sessions.forEach(s => {
        // ensure createdAt exists for grouping; fallback to now
        const created = s.createdAt || new Date().toISOString();
        const g = relativeGroup(created);
        (groups[g] = groups[g] || []).push(s);
    });

    let html = '';
    groupOrder.forEach(label => {
        if (!groups[label]) return;
        html += `<div class="conv-group-label">${label}</div>`;
        groups[label].forEach(s => {
            const active = currentSession && s.id === currentSession.id ? 'active' : '';
            const title = escapeHtml(s.title || 'New Conversation');
            html += `
            <div class="conv-item ${active}" onclick="switchSession('${s.id}')">
                <svg class="conv-icon" width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"></path>
                </svg>
                <span class="conv-title">${title}</span>
                <button class="conv-delete" onclick="event.stopPropagation();deleteConv('${s.id}')" title="Delete conversation">
                    <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">
                        <line x1="18" y1="6" x2="6" y2="18"></line>
                        <line x1="6" y1="6" x2="18" y2="18"></line>
                    </svg>
                </button>
            </div>`;
        });
    });
    convListEl.innerHTML = html;
}

/* ═══════════════════════════════════════════════════════
   KNOWLEDGE BASE TOGGLE
   ═══════════════════════════════════════════════════════ */
function toggleKnowledge(btn) {
    btn.classList.toggle('open');
    document.getElementById('knowledgeBody').classList.toggle('open');
}

/* ═══════════════════════════════════════════════════════
   CONVERSATION SWITCHING
   ═══════════════════════════════════════════════════════ */
async function switchSession(id) {
    if (currentSession && currentSession.id === id) return;
    const s = sessions.find(x => x.id === id);
    if (!s) {
        // try reloading sessions from server
        await loadSessionsFromServer();
        const found = sessions.find(x => x.id === id);
        if (!found) return;
        currentSession = found;
    } else {
        currentSession = s;
    }
    renderSidebar();
    clearMessages();
    // update header title when switching
    if (sessionTitleEl) sessionTitleEl.textContent = currentSession.title || 'New Conversation';
    await loadSessionMessages(id);
}

async function loadSessionMessages(sessionId) {
    try {
        const res  = await fetch(`/api/sessions/${sessionId}/messages`);
        const data = await res.json();
        const msgs = data.messages || [];
        if (msgs.length > 0) {
            msgs.forEach(m => {
                const role = (m.role || '').toLowerCase() === 'user' ? 'user' : 'bot';
                appendMessage(role, m.content, false);
            });
            messagesEl.scrollTop = messagesEl.scrollHeight;
            // typeset any LaTeX in the newly added messages
            if (window.MathJax && MathJax.typesetPromise) MathJax.typesetPromise();
        } else {
            showWelcomeCard();
        }
    } catch {
        showWelcomeCard();
    }
}

async function newChat() {
    // Request backend to clear current session and get a fresh session id
    try {
        const res = await fetch('/api/chat/clear', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ sessionId: currentSession ? currentSession.id : null })
        });
        const data = await res.json();
        const newId = data.sessionId || crypto.randomUUID();
        // insert locally so UI shows it immediately
        currentSession = { id: newId, title: 'New Conversation', createdAt: new Date().toISOString() };
        if (sessionTitleEl) sessionTitleEl.textContent = currentSession.title;
        sessions.unshift(currentSession);
        renderSidebar();
        clearMessages();
        showWelcomeCard();
        messageInput.focus();
    } catch (e) {
        // fallback to purely local new session
        currentSession = createLocalSession();
        if (sessionTitleEl) sessionTitleEl.textContent = currentSession.title;
        renderSidebar();
        clearMessages();
        showWelcomeCard();
        messageInput.focus();
    }
}

async function deleteConv(id) {
    if (!confirm('Delete this conversation? This cannot be undone.')) return;
    try { await fetch(`/api/sessions/${id}`, { method: 'DELETE' }); } catch { /* ok */ }

    // Refresh sessions from server
    await loadSessionsFromServer();

    // Update local sessions array and currentSession
    sessions = sessions.filter(s => s.id !== id);

    if (currentSession && currentSession.id === id) {
        if (sessions.length > 0) {
            currentSession = sessions[0];
            renderSidebar();
            clearMessages();
            await loadSessionMessages(currentSession.id);
        } else {
            currentSession = createLocalSession();
            renderSidebar();
            clearMessages();
            showWelcomeCard();
        }
    } else {
        renderSidebar();
    }
}

/* ═══════════════════════════════════════════════════════
   MESSAGES
   ═══════════════════════════════════════════════════════ */
function clearMessages() {
    messagesEl.innerHTML = '';
}

function showWelcomeCard() {
    const titleText = (currentSession && currentSession.title) ? escapeHtml(currentSession.title) : 'New Conversation';
    messagesEl.innerHTML = `
    <div class="welcome-card">
        <div class="welcome-header">
            <div class="welcome-title-row">
                <h1 id="cardSessionTitle" class="welcome-title">${titleText}</h1>
                <button id="cardEditBtn" class="icon-btn" title="Rename conversation">
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                        <path d="M3 17.25V21h3.75L17.81 9.94l-3.75-3.75L3 17.25z"></path>
                        <path d="M20.71 7.04a1 1 0 0 0 0-1.41l-2.34-2.34a1 1 0 0 0-1.41 0l-1.83 1.83 3.75 3.75 1.83-1.83z"></path>
                    </svg>
                </button>
            </div>
        </div>
        <p class="welcome-sub">
            I remember our conversations across sessions — tell me your name, upload documents, and ask anything.<br>
            History is saved in <strong>MySQL</strong> and survives restarts.
        </p>
        <div class="welcome-chips">
            <button class="chip" onclick="fillInput(this)">Summarize the document</button>
            <button class="chip" onclick="fillInput(this)">What are the key points?</button>
            <button class="chip" onclick="fillInput(this)">My name is...</button>
            <button class="chip" onclick="fillInput(this)">List all topics covered</button>
        </div>
        <div id="cardTitleEdit" class="welcome-title-edit" style="display:none">
            <input id="cardTitleInput" type="text" maxlength="255" />
            <button id="cardSaveTitleBtn">Save</button>
            <button id="cardCancelTitleBtn">Cancel</button>
        </div>
    </div>`;

    // Wire card-level rename handlers
    try {
        const card = messagesEl.querySelector('.welcome-card');
        const editBtn = card.querySelector('#cardEditBtn');
        const editBox = card.querySelector('#cardTitleEdit');
        const input = card.querySelector('#cardTitleInput');
        const saveBtn = card.querySelector('#cardSaveTitleBtn');
        const cancelBtn = card.querySelector('#cardCancelTitleBtn');
        const titleEl = card.querySelector('#cardSessionTitle');

        if (editBtn) {
            editBtn.addEventListener('click', () => {
                if (!editBox || !input) return;
                input.value = currentSession ? (currentSession.title || '') : '';
                editBox.style.display = 'flex';
                input.focus();
            });
        }
        if (cancelBtn) {
            cancelBtn.addEventListener('click', () => { if (editBox) editBox.style.display = 'none'; });
        }
        if (saveBtn) {
            saveBtn.addEventListener('click', async () => {
                if (!input || !currentSession) return;
                const newTitle = input.value.trim();
                try {
                    const res = await fetch(`/api/sessions/${currentSession.id}/rename`, {
                        method: 'PUT', headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ title: newTitle })
                    });
                    if (res.ok) {
                        const data = await res.json();
                        currentSession.title = data.title || newTitle || 'New Conversation';
                        if (sessionTitleEl) sessionTitleEl.textContent = currentSession.title;
                        // update local sessions list if present
                        const idx = sessions.findIndex(s => s.id === currentSession.id);
                        if (idx >= 0) sessions[idx].title = currentSession.title;
                        // update UI
                        if (titleEl) titleEl.textContent = escapeHtml(currentSession.title);
                        renderSidebar();
                        showToast('Conversation renamed', 'success');
                    } else {
                        showToast('Rename failed', 'error');
                    }
                } catch (e) {
                    // offline/local fallback
                    currentSession.title = newTitle || 'New Conversation';
                    if (sessionTitleEl) sessionTitleEl.textContent = currentSession.title;
                    const idx = sessions.findIndex(s => s.id === currentSession.id);
                    if (idx >= 0) sessions[idx].title = currentSession.title;
                    if (titleEl) titleEl.textContent = escapeHtml(currentSession.title);
                    renderSidebar();
                    showToast('Renamed locally (offline)', 'default');
                } finally {
                    if (editBox) editBox.style.display = 'none';
                }
            });
        }
    } catch (e) { /* ignore wiring errors */ }
}

function fillInput(el) {
    const card = messagesEl.querySelector('.welcome-card');
    if (card) card.remove();
    messageInput.value = el.textContent;
    messageInput.focus();
    messageInput.dispatchEvent(new Event('input'));
}

function removeWelcomeCard() {
    const c = messagesEl.querySelector('.welcome-card');
    if (c) c.remove();
}

function appendMessage(role, text, scroll = true) {
    removeWelcomeCard();
    const isUser = role === 'user';
    const div = document.createElement('div');
    div.className = `message message-${isUser ? 'user' : 'bot'}`;
    div.innerHTML = `
        <div class="avatar ${isUser ? 'user-avatar' : 'bot-avatar'}">${isUser ? 'You' : 'AI'}</div>
        <div class="message-content">${formatMarkdown(text)}</div>`;
    messagesEl.appendChild(div);
    if (scroll) messagesEl.scrollTop = messagesEl.scrollHeight;

    // Syntax highlight any code blocks we just inserted
    if (window.hljs && hljs.highlightElement) {
        try {
            div.querySelectorAll('pre code').forEach(el => {
                try { hljs.highlightElement(el); } catch(e) { /* ignore */ }
            });
        } catch(e) { /* ignore */ }
    }

    // Add toolbar + expand/copy behavior to code blocks (allow vertical and horizontal resize/expand)
    try {
        div.querySelectorAll('pre code').forEach(codeEl => {
            if (codeEl.dataset.processed) return;
            codeEl.dataset.processed = '1';

            const pre = codeEl.closest('pre');
            // make pre resizable and scrollable
            pre.style.overflow = 'auto';
            pre.style.resize = 'both';
            pre.style.maxHeight = '60vh';

            // wrap pre in container to position toolbar
            const wrap = document.createElement('div');
            wrap.className = 'code-wrap';
            pre.parentNode.replaceChild(wrap, pre);
            wrap.appendChild(pre);

            // toolbar
            const toolbar = document.createElement('div');
            toolbar.className = 'code-toolbar';

            // Copy button placed in toolbar (icon + label on hover)
            const btnCopy = document.createElement('button');
            btnCopy.type = 'button';
            btnCopy.className = 'code-btn code-copy-btn';
            btnCopy.setAttribute('aria-label', 'Copy code');
            btnCopy.setAttribute('data-tooltip', 'Copy');
            btnCopy.innerHTML = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.6" style="vertical-align:middle"><rect x="9" y="9" width="10" height="10" rx="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg>';

            // Expand/Collapse button (small, top-right)
            const btnExpand = document.createElement('button');
            btnExpand.type = 'button';
            btnExpand.className = 'code-btn code-expand';
            btnExpand.setAttribute('aria-label', 'Expand code');
            btnExpand.innerHTML = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.6" style="vertical-align:middle"><polyline points="9 14 9 21 16 21"></polyline><polyline points="15 9 15 3 8 3"></polyline><polyline points="21 9 21 16 16 16"></polyline><polyline points="3 15 3 8 8 8"></polyline></svg>';

            toolbar.appendChild(btnCopy);
            toolbar.appendChild(btnExpand);
            wrap.appendChild(toolbar);

            // helper to open/close expanded state and manage body scroll
            const openExpanded = () => {
                wrap.classList.add('expanded');
                document.body.style.overflow = 'hidden';
                // ensure pre takes full space
                pre.style.height = '100%';
                pre.style.maxHeight = 'none';
                // listen for esc to close
                const onKey = (e) => { if (e.key === 'Escape') closeExpanded(); };
                document.addEventListener('keydown', onKey);
                wrap._onKey = onKey;
            };
            const closeExpanded = () => {
                wrap.classList.remove('expanded');
                document.body.style.overflow = '';
                pre.style.height = 'auto';
                pre.style.maxHeight = '60vh';
                if (wrap._onKey) document.removeEventListener('keydown', wrap._onKey);
            };

            // click outside (on overlay background) closes when expanded
            wrap.addEventListener('click', (ev) => {
                if (wrap.classList.contains('expanded') && ev.target === wrap) {
                    closeExpanded();
                }
            });

            // expand toggle
            btnExpand.addEventListener('click', () => {
                if (wrap.classList.contains('expanded')) closeExpanded(); else openExpanded();
            });

            // copy button behavior (with tooltip feedback)
            btnCopy.addEventListener('click', async () => {
                const showCopied = () => {
                    btnCopy.classList.add('copied');
                    btnCopy.setAttribute('data-tooltip', 'Copied');
                    setTimeout(() => { btnCopy.classList.remove('copied'); btnCopy.setAttribute('data-tooltip', 'Copy'); }, 1400);
                };
                try {
                    await navigator.clipboard.writeText(codeEl.textContent);
                    showCopied();
                    showToast('Code copied', 'success');
                } catch (e) {
                    try {
                        const ta = document.createElement('textarea');
                        ta.value = codeEl.textContent;
                        ta.style.position = 'absolute';
                        ta.style.left = '-9999px';
                        document.body.appendChild(ta);
                        ta.select();
                        document.execCommand('copy');
                        ta.remove();
                        showCopied();
                        showToast('Code copied', 'success');
                    } catch (err) {
                        showToast('Copy failed', 'error');
                    }
                }
            });

            // Auto-expand removed: code blocks should only expand when user clicks the expand button
        });
    } catch (e) { /* ignore */ }

    // Render LaTeX (MathJax) for dynamic content
    if (window.MathJax && MathJax.typesetPromise) {
        try { MathJax.typesetPromise([div]); }
        catch (e) { /* ignore MathJax errors */ }
    }
}

function showTyping() {
    removeWelcomeCard();
    const div = document.createElement('div');
    div.id = 'typing';
    div.className = 'message message-bot';
    div.innerHTML = `
        <div class="avatar bot-avatar">AI</div>
        <div class="message-content"><div class="dots">
            <span></span><span></span><span></span>
        </div></div>`;
    messagesEl.appendChild(div);
    messagesEl.scrollTop = messagesEl.scrollHeight;
}

function removeTyping() {
    const t = document.getElementById('typing');
    if (t) t.remove();
}

/* ═══════════════════════════════════════════════════════
   MARKDOWN FORMATTER
   ═══════════════════════════════════════════════════════ */
function formatMarkdown(text) {
    // 1) Extract fenced code blocks and replace with placeholders
    const codeBlocks = [];
    const placeholder = (i) => `@@CODE_BLOCK_${i}@@`;
    text = text.replace(/```(\w*)\n?([\s\S]*?)```/g, (_, lang, code) => {
        const idx = codeBlocks.length;
        codeBlocks.push({ lang: lang || '', code: code });
        return placeholder(idx);
    });

    // 2) Escape the rest of the text
    let s = escapeHtml(text);

    // 3) Inline code (keep as HTML <code>)
    s = s.replace(/`([^`\n]+)`/g, '<code>$1</code>');

    // 4) Bold & italic
    s = s.replace(/\*\*\*(.*?)\*\*\*/g, '<strong><em>$1</em></strong>');
    s = s.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
    s = s.replace(/\*(.*?)\*/g, '<em>$1</em>');

    // 5) Headers
    s = s.replace(/^### (.*)/gm, '<h3>$1</h3>');
    s = s.replace(/^## (.*)/gm,  '<h2>$1</h2>');
    s = s.replace(/^# (.*)/gm,   '<h1>$1</h1>');

    // 6) Blockquote
    s = s.replace(/^&gt; (.*)/gm, '<blockquote>$1</blockquote>');

    // 7) Bullet lists
    s = s.replace(/^[-*] (.*)/gm, '<li>$1</li>');
    s = s.replace(/(<li>.*?<\/li>)(\n<li>)/gs, '$1$2');
    s = s.replace(/(<li>[\s\S]*?<\/li>)/g, '<ul>$1</ul>');

    // 8) Paragraphs and remaining newlines: convert double newlines to paragraph breaks, single newlines to <br>
    s = s.replace(/\n\n+/g, '</p><p>');
    s = s.replace(/\n/g, '<br>');

    // 9) Wrap in paragraph if not starting with block element
    if (!s.match(/^<(h[1-6]|ul|ol|pre|blockquote)/)) {
        s = '<p>' + s + '</p>';
    }

    // 10) Restore code blocks placeholders with properly escaped content (preserve newlines inside <pre>)
    codeBlocks.forEach((cb, i) => {
        // normalize newlines and attempt to fix adjacent includes that got concatenated
        let raw = cb.code.replace(/\r\n/g, '\n');
        // Insert newline between adjacent #include occurrences if they were concatenated
        raw = raw.replace(/(#include\s*(?:<[^>]+>|"[^"]+")?)(?=#include)/g, '$1\n');
        // Ensure comments are intact (no trimming) - keep raw as-is
        const safeCode = escapeHtml(raw);
        const langClass = cb.lang ? ` class="language-${cb.lang}"` : '';
        s = s.replace(placeholder(i), `<pre><code${langClass}>${safeCode}</code></pre>`);
    });

    return s;
}

function escapeHtml(s) {
    return String(s)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
}

/* ═══════════════════════════════════════════════════════
   SEND MESSAGE
   ═══════════════════════════════════════════════════════ */
async function sendMessage() {
    const text = messageInput.value.trim();
    if (!text || isSending) return;

    if (!currentSession) {
        currentSession = createLocalSession();
        renderSidebar();
    }

    isSending = true;
    appendMessage('user', text);
    messageInput.value = '';
    messageInput.style.height = 'auto';
    sendBtn.disabled = true;
    showTyping();

    try {
        const res  = await fetch('/api/chat', {
            method:  'POST',
            headers: { 'Content-Type': 'application/json' },
            body:    JSON.stringify({ message: text, sessionId: currentSession.id })
        });
        const data = await res.json();
        removeTyping();

        if (res.ok) {
            appendMessage('bot', data.response);
            // Ensure LaTeX in bot response renders
            if (window.MathJax && MathJax.typesetPromise) MathJax.typesetPromise();

            // After saving message on server, refresh sessions so titles/counts update
            await loadSessionsFromServer();
            const updated = sessions.find(s => s.id === currentSession.id);
            if (updated) currentSession.title = updated.title || currentSession.title;
            renderSidebar();
        } else {
            appendMessage('bot', '⚠️ ' + (data.error || 'Something went wrong.'));
            if (window.MathJax && MathJax.typesetPromise) MathJax.typesetPromise();
        }
    } catch {
        removeTyping();
        appendMessage('bot', '⚠️ Cannot reach the server. Is the backend running?');
        if (window.MathJax && MathJax.typesetPromise) MathJax.typesetPromise();
    } finally {
        isSending = false;
        sendBtn.disabled = false;
        messageInput.focus();
    }
}

/* Input events */
sendBtn.addEventListener('click', sendMessage);
messageInput.addEventListener('keydown', e => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(); }
});
messageInput.addEventListener('input', () => {
    messageInput.style.height = 'auto';
    messageInput.style.height = Math.min(messageInput.scrollHeight, 150) + 'px';
});

/* ═══════════════════════════════════════════════════════
   TOAST
   ═══════════════════════════════════════════════════════ */
let _toastTimer;
function showToast(msg, type = 'default') {
    let t = document.getElementById('toast');
    if (!t) { t = document.createElement('div'); t.id = 'toast'; document.body.appendChild(t); }
    clearTimeout(_toastTimer);
    t.textContent = msg;
    t.className = `toast toast-${type}`;
    t.getBoundingClientRect();
    t.classList.add('show');
    _toastTimer = setTimeout(() => t.classList.remove('show'), 3200);
}

/* ═══════════════════════════════════════════════════════
   FILE UPLOAD
   ═══════════════════════════════════════════════════════ */
uploadTrigger.addEventListener('click', () => {
    // Open knowledge base section and trigger file picker
    const body   = document.getElementById('knowledgeBody');
    const toggle = document.querySelector('.knowledge-toggle');
    if (!body.classList.contains('open')) {
        toggle.classList.add('open');
        body.classList.add('open');
    }
    fileInput.click();
});

dropZone.addEventListener('click', () => fileInput.click());
dropZone.addEventListener('dragover', e => { e.preventDefault(); dropZone.classList.add('drag-over'); });
dropZone.addEventListener('dragleave', () => dropZone.classList.remove('drag-over'));
dropZone.addEventListener('drop', async e => {
    e.preventDefault();
    dropZone.classList.remove('drag-over');
    for (const f of [...e.dataTransfer.files]) await uploadFile(f);
});
fileInput.addEventListener('change', async () => {
    for (const f of [...fileInput.files]) await uploadFile(f);
    fileInput.value = '';
});

async function uploadFile(file) {
    progressWrap.style.display = 'block';
    progressFill.style.width = '0%';
    progressLabel.textContent = `Uploading ${file.name}…`;

    let prog = 0;
    const ticker = setInterval(() => {
        prog = Math.min(prog + Math.random() * 14, 85);
        progressFill.style.width = prog + '%';
    }, 160);

    try {
        const fd  = new FormData();
        fd.append('file', file);
        const res  = await fetch('/api/upload', { method: 'POST', body: fd });
        const data = await res.json();
        clearInterval(ticker);
        progressFill.style.width = '100%';

        if (res.ok) {
            progressLabel.textContent = '✓ ' + data.message;
            addFileToList(file.name);
            showToast('✓ Indexed: ' + file.name, 'success');
        } else {
            progressLabel.textContent = '✗ ' + (data.error || 'Upload failed');
            showToast('✗ ' + (data.error || 'Upload failed'), 'error');
        }
    } catch {
        clearInterval(ticker);
        progressLabel.textContent = '✗ Connection error';
        showToast('✗ Upload error', 'error');
    } finally {
        setTimeout(() => { progressWrap.style.display = 'none'; }, 3000);
    }
}

function addFileToList(name) {
    const li = document.createElement('li');
    li.className = 'file-item-sm';
    li.innerHTML = `<span style="color:var(--green)">✓</span>${escapeHtml(name)}`;
    fileListEl.appendChild(li);
}

/* ═══════════════════════════════════════════════════════
   START
   ═══════════════════════════════════════════════════════ */
init();
